import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Minus, Square, X as XIcon } from 'lucide-react';
import { api } from './api';
import { getCurrentWindow } from '@tauri-apps/api/window';
import { WebviewWindow } from '@tauri-apps/api/webviewWindow';
import { listen } from '@tauri-apps/api/event';

import MenuBar from './components/MenuBar';
import Toolbar from './components/Toolbar';
import Sidebar from './components/Sidebar';
import DownloadsTable from './components/DownloadsTable';

import OptionsDialog from './components/Dialogs/OptionsDialog';
import SchedulerDialog from './components/Dialogs/SchedulerDialog';
import DeleteDialog from './components/Dialogs/DeleteDialog';
import RefreshUrlDialog from './components/Dialogs/RefreshUrlDialog';
import { GrabberDialog } from './components/Dialogs/GrabberDialog';
import { SpiderDialog } from './components/Dialogs/SpiderDialog';
import PropertiesDialog from './components/Dialogs/PropertiesDialog';
import { playSound } from './audio';
import { Toaster, toast } from 'sonner';
import { readText } from '@tauri-apps/plugin-clipboard-manager';

import { useDownloadStore, initDownloadStoreSSE } from './stores/downloadStore';
import { useConfigStore } from './stores/configStore';
import { useUiStore } from './stores/uiStore';
import { useKeyboardShortcuts } from './hooks/useKeyboardShortcuts';

export default function App() {
  const { selectedIds, filters, sortBy, sortDirection } = useDownloadStore();
  const downloadsMap = useDownloadStore(s => s.downloads);
  const downloads = useDownloadStore(s => s.getSortedAndFilteredDownloads());
  const setDownloads = useDownloadStore(state => state.setDownloads);
  const selectDownload = useDownloadStore(state => state.selectDownload);

  const fetchConfig = useConfigStore(state => state.fetchConfig);
  const config = useConfigStore(state => state.config);

  const [isConnected, setIsConnected] = useState(true);

  const [activeCategory, setActiveCategory] = useState('All Downloads');
  const [searchQuery, setSearchQuery] = useState('');
  const searchInputRef = useRef<HTMLInputElement>(null);

  const ui = useUiStore();

  const spawnAddUrlWindow = async (url = '', filename = '') => {
    try {
      const existing = await WebviewWindow.getByLabel('add-url');
      if (existing) {
        if (url) {
          const { emit } = await import('@tauri-apps/api/event');
          await emit('update-add-url', { url, filename });
        }
        await existing.unminimize().catch(console.error);
        await existing.setAlwaysOnTop(true).catch(console.error);
        await existing.setAlwaysOnTop(false).catch(console.error);
        await existing.setFocus().catch(console.error);
        return;
      }

      const webview = new WebviewWindow('add-url', {
        url: `/?window=addUrl&url=${encodeURIComponent(url)}&filename=${encodeURIComponent(filename)}`,
        title: 'Add New Download',
        width: 560,
        height: 620,
        minWidth: 480,
        minHeight: 520,
        resizable: true,
        maximizable: false,
        decorations: false,
        center: true,
        focus: true,
        alwaysOnTop: true
      });

      webview.once('tauri://created', () => {
        webview.setFocus().catch(console.error);
      });
    } catch (e) {
      console.error(e);
    }
  };

  useKeyboardShortcuts(searchInputRef, spawnAddUrlWindow);

  useEffect(() => {
    let unlisten: () => void;

    const setup = async () => {
      unlisten = await listen<{ paths: string[] }>('tauri://drop', (event) => {
        const paths = event.payload.paths || (event.payload as any);
        if (Array.isArray(paths) && paths.length > 0) {
          // Open Add URL window with the first dropped file/url
          spawnAddUrlWindow(paths[0], '');
        }
      });
    };

    setup();
    return () => { if (unlisten) unlisten(); };
  }, []);

  const completedWindowsShown = useRef<Set<string>>(new Set());
  const activeProgressWindows = useRef<Set<string>>(new Set());
  const lastSSEUpdate = useRef<number>(Date.now());

  const spawnDownloadCompleteWindow = (id: string) => {
    if (completedWindowsShown.current.has(id)) return;
    completedWindowsShown.current.add(id);
    try {
      const webview = new WebviewWindow(`complete-${id}`, {
        url: `/?window=downloadComplete&id=${encodeURIComponent(id)}`,
        title: 'Download Complete',
        width: 520,
        height: 300,
        resizable: false,
        decorations: false,
        center: true,
        focus: true,
        alwaysOnTop: true
      });
      webview.once('tauri://created', () => {
        webview.setFocus().catch(console.error);
      });
    } catch (e) {
      console.error(e);
    }
  };

  const spawnProgressWindow = useCallback(async (id: string) => {
    if (activeProgressWindows.current.has(id)) return;
    activeProgressWindows.current.add(id);

    const item = useDownloadStore.getState().downloads[id];
    if (item) {
      localStorage.setItem(`vajra_progress_init_${id}`, JSON.stringify(item));
    }

    try {
      const existing = await WebviewWindow.getByLabel(`progress-${id}`);
      if (existing) {
        await existing.setFocus();
        return;
      }
      const webview = new WebviewWindow(`progress-${id}`, {
        url: `/?window=progress&id=${encodeURIComponent(id)}`,
        title: 'Download Progress',
        width: 520,
        height: 520,
        resizable: true,
        maximizable: false,
        center: true,
        decorations: false,
        alwaysOnTop: false,
      });

      webview.once('tauri://created', () => {
        webview.setFocus().catch(console.error);
      });

      webview.once('tauri://destroyed', () => {
        activeProgressWindows.current.delete(id);
      });
    } catch (e) {
      console.error(e);
      activeProgressWindows.current.delete(id);
    }
  }, []);

  const fetchDownloads = useCallback(() => {
    api.list().then(res => {
      useDownloadStore.getState().setDownloads(res.items || []);
      lastSSEUpdate.current = Date.now();
    }).catch(console.error);
  }, []);

  useEffect(() => {
    fetchDownloads();
    fetchConfig();

    const interval = setInterval(() => {
      if (Date.now() - lastSSEUpdate.current > 10000) {
        fetchDownloads();
      }
    }, 30000);

    const healthInterval = setInterval(() => {
      api.health().then(res => {
        if (res?.status === 'ok') {
          setIsConnected(true);
        }
      }).catch(() => {
        setIsConnected(false);
      });
    }, 5000);

    const unlistenPromise = listen('open-progress-window', (e) => {
      spawnProgressWindow(e.payload as string);
    });

    initDownloadStoreSSE();

    // Re-check completed/failed to spawn windows or sounds from the store changes if needed
    const unsub = useDownloadStore.subscribe((state, prevState) => {
       // Diff state here if we want to trigger sounds. 
       // For now, simpler to just use SSE for events.
    });

    return () => {
      clearInterval(interval);
      clearInterval(healthInterval);
      unlistenPromise.then(fn => fn()).catch(console.error);
      unsub();
    };
  }, [spawnProgressWindow, fetchDownloads, fetchConfig]);

  // Drag and Drop
  useEffect(() => {
    let unlisten: (() => void) | undefined;
    getCurrentWindow().onDragDropEvent((event) => {
      if (event.payload.type === 'drop') {
        const files = event.payload.paths;
        if (files && files.length > 0) {
          const file = files[0];
          if (file.toLowerCase().endsWith('.torrent')) {
            spawnAddUrlWindow(file);
          }
        }
      }
    }).then(fn => {
      unlisten = fn;
    }).catch(console.error);

    return () => {
      if (unlisten) unlisten();
    };
  }, []);

  // Clipboard monitor
  const lastClipboardText = useRef<string | null>(null);
  useEffect(() => {
    let unlisten: (() => void) | undefined;
    const setupClipboardListener = async () => {
      try {
        unlisten = await listen('plugin:clipboard://clipboard-monitor/update', async () => {
          try {
            const text = await readText();
            if (text && text !== lastClipboardText.current) {
              lastClipboardText.current = text;
              const trimmed = text.trim();
              const isUrl = /^https?:\/\//i.test(trimmed) || /^magnet:\?/i.test(trimmed);

              if (isUrl) {
                toast.info('Download Link Detected - Click to Add', {
                  description: trimmed.length > 50 ? trimmed.substring(0, 47) + '...' : trimmed,
                  action: {
                    label: 'Add Download',
                    onClick: () => spawnAddUrlWindow(trimmed)
                  },
                  duration: 5000,
                });
              }
            }
          } catch (e) {}
        });
      } catch (e) {
        console.error("Failed to setup clipboard listener", e);
      }
    };
    setupClipboardListener();
    return () => { if (unlisten) unlisten(); };
  }, []);

  const handleMinimize = () => getCurrentWindow().minimize().catch(console.error);
  const handleMaximize = () => getCurrentWindow().toggleMaximize().catch(console.error);
  const handleClose = () => getCurrentWindow().close().catch(console.error);

  const handleSelect = useCallback((id: string, shift: boolean, ctrl: boolean) => {
    if (ctrl) {
      useDownloadStore.getState().selectDownload(id, true);
    } else {
      useDownloadStore.getState().clearSelection();
      useDownloadStore.getState().selectDownload(id, false);
    }
  }, []);

  const handleSelectAll = useCallback((ids: string[]) => {
    useDownloadStore.getState().selectAll();
  }, []);

  const handlePause = async (id: string) => {
    if (!id) return;
    try { 
      await api.patch(id, { action: 'pause' }); 
      fetchDownloads();
    } catch(e) { console.error(e); }
  };

  const handleResume = async (id: string) => {
    if (!id) return;
    try { 
      await api.patch(id, { action: 'resume' }); 
      fetchDownloads();
    } catch(e) { console.error(e); }
  };

  const executeDeleteSelected = async (deleteFromDisk: boolean, remember: boolean = false) => {
    ui.setDeleteModalOpen(false);
    if (remember) {
      localStorage.setItem('vajra_delete_preference', deleteFromDisk ? 'disk' : 'list_only');
    }
    const ids = [...selectedIds];
    useDownloadStore.getState().clearSelection();
    for (const id of ids) {
      try {
        await api.remove(id, deleteFromDisk);
      } catch (e) {
        console.error(e);
      }
    }
    fetchDownloads();
  };

  const handleDeleteCompleted = async () => {
    const completed = downloads.filter(d => d.status === 'completed');
    for (const d of completed) {
      try {
        await api.remove(d.id, false);
      } catch (e) {}
    }
    fetchDownloads();
    useDownloadStore.getState().clearSelection();
  };

  const handlePauseSelected = async () => {
    for (const id of selectedIds) {
      const d = downloadsMap[id];
      if (d && (d.status === 'downloading' || d.status === 'connecting')) await handlePause(id);
    }
  };

  const handleResumeSelected = async () => {
    for (const id of selectedIds) {
      const d = downloadsMap[id];
      if (d && (d.status === 'paused' || d.status === 'error' || d.status === 'failed')) {
        await handleResume(id);
      }
    }
  };

  const handleResumeAll = async () => {
    const pausedOrError = downloads.filter((d) => d.status === 'paused' || d.status === 'error' || d.status === 'failed');
    for (const d of pausedOrError) {
      await handleResume(d.id);
    }
  };

  const handleStopAll = async () => {
    const active = downloads.filter((d) => d.status === 'downloading' || d.status === 'connecting');
    for (const d of active) {
      await handlePause(d.id);
    }
  };

  const handleGridAction = async (item: any, action: string) => {
    if (action === 'pause') handlePause(item.id);
    else if (action === 'resume') handleResume(item.id);
    else if (action === 'delete') {
      useDownloadStore.getState().clearSelection();
      useDownloadStore.getState().selectDownload(item.id, false);
      ui.setDeleteModalOpen(true);
    }
    else if (action === 'open') {
      try {
        const { invoke } = await import('@tauri-apps/api/core');
        await invoke('open_file_path', { path: item.output_path });
      } catch (e) { console.error("Failed to open file", e); }
    }
    else if (action === 'properties') {
      ui.setPropertiesModalItem(item);
      ui.setPropertiesModalOpen(true);
    }
    else if (action === 'refresh_url') {
      ui.setRefreshModalItem(item);
      ui.setRefreshModalOpen(true);
    }
    else if (action === 'show_progress') {
      spawnProgressWindow(item.id);
    }
  };

  const handleDoubleClick = useCallback((item: any) => {
    if (item.status === 'completed') {
      handleGridAction(item, 'open');
    } else {
      spawnProgressWindow(item.id);
    }
  }, [spawnProgressWindow]);

  const canResume = useMemo(() => downloads.some(d => selectedIds.includes(d.id) && (d.status === 'paused' || d.status === 'error' || d.status === 'failed')), [downloads, selectedIds]);
  const canPause = useMemo(() => downloads.some(d => selectedIds.includes(d.id) && (d.status === 'downloading' || d.status === 'connecting')), [downloads, selectedIds]);
  const canStopAll = useMemo(() => downloads.some(d => d.status === 'downloading' || d.status === 'connecting'), [downloads]);
  const canDelete = selectedIds.length > 0;

  const filteredDownloads = useMemo(() => {
    if (!searchQuery.trim()) return downloads;
    const q = searchQuery.toLowerCase();
    return downloads.filter(d => 
      (d.filename && d.filename.toLowerCase().includes(q)) ||
      (d.url && d.url.toLowerCase().includes(q))
    );
  }, [downloads, searchQuery]);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', overflow: 'hidden', fontFamily: 'var(--font-sans)', backgroundColor: 'var(--color-surface)', color: 'var(--color-text-1)' }}>
      <Toaster theme="dark" position="bottom-right" />

      {/* OS window controls — top-right overlay */}
      <div className="absolute no-drag" style={{ top: 0, right: 0, height: 32, display: 'flex', zIndex: 50 }}>
        {([
          { icon: <Minus size={12} />, title: 'Minimize', action: handleMinimize, danger: false },
          { icon: <Square size={11} />, title: 'Maximize', action: handleMaximize, danger: false },
          { icon: <XIcon size={13} />, title: 'Close',    action: handleClose,    danger: true  },
        ] as { icon: React.ReactNode; title: string; action: () => void; danger: boolean }[]).map(({ icon, title, action, danger }) => (
          <button
            key={title}
            title={title}
            onClick={action}
            style={{ width: 44, height: 32, border: 'none', background: 'transparent', color: 'var(--color-text-3)', cursor: 'default', display: 'flex', alignItems: 'center', justifyContent: 'center', transition: 'background-color var(--transition-fast), color var(--transition-fast)' }}
            onMouseEnter={e => { (e.currentTarget as HTMLButtonElement).style.backgroundColor = danger ? 'var(--color-error)' : 'var(--color-surface-elevated)'; (e.currentTarget as HTMLButtonElement).style.color = danger ? '#fff' : 'var(--color-text-1)'; }}
            onMouseLeave={e => { (e.currentTarget as HTMLButtonElement).style.backgroundColor = 'transparent'; (e.currentTarget as HTMLButtonElement).style.color = 'var(--color-text-3)'; }}
          >{icon}</button>
        ))}
      </div>

      {/* Menu bar + drag region */}
      <div className="drag-region" style={{ height: 32, borderBottom: '1px solid var(--color-border)', backgroundColor: 'var(--color-surface-raised)', display: 'flex', alignItems: 'center', paddingLeft: 8, flexShrink: 0 }}>
        <div className="no-drag">
          <MenuBar
            onAdd={() => spawnAddUrlWindow('')}
            onOptions={() => ui.setSettingsModalOpen(true)}
            onPauseAll={handleStopAll}
            onResumeAll={handleResumeAll}
          />
        </div>
      </div>

      {/* Toolbar */}
      <div className="no-drag">
        <Toolbar
          selectedIds={selectedIds}
          onAdd={() => spawnAddUrlWindow('')}
          onResumeSelected={handleResumeSelected}
          onPauseSelected={handlePauseSelected}
          onStopAll={handleStopAll}
          onDeleteSelected={() => {
            const pref = localStorage.getItem('vajra_delete_preference');
            if (pref) executeDeleteSelected(pref === 'disk', false);
            else ui.setDeleteModalOpen(true);
          }}
          onDeleteCompleted={handleDeleteCompleted}
          onOptions={() => ui.setSettingsModalOpen(true)}
          onScheduler={() => ui.setSchedulerModalOpen(true)}
          onGrabber={() => ui.setGrabberModalOpen(true)}
          onSpider={() => ui.setSpiderModalOpen(true)}
          onHelp={() => api.openBrowserSetup()}
          canResume={canResume}
          canPause={canPause}
          canStopAll={canStopAll}
          canDelete={canDelete}
          canDeleteCompleted={downloads.some(d => d.status === 'completed')}
          onShowProgress={() => {
            if (selectedIds.length === 1) {
              const d = downloadsMap[selectedIds[0]];
              if (d?.status === 'completed') {
                ui.setPropertiesModalItem(d);
                ui.setPropertiesModalOpen(true);
              } else spawnProgressWindow(selectedIds[0]);
            }
          }}
          canShowProgress={selectedIds.length === 1}
          isSelectedCompleted={(() => {
            if (selectedIds.length !== 1) return false;
            const d = downloadsMap[selectedIds[0]];
            return d?.status === 'completed';
          })()}
        >
          <div className="flex-1 min-w-[12px]" />
          <div className="relative flex items-center pr-2">
            <input
              ref={searchInputRef}
              type="text"
              placeholder="Search (Ctrl+F)"
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              className="bg-[var(--color-surface)] border border-[var(--color-border)] text-[var(--color-text-1)] text-xs rounded px-2 py-1 w-48 focus:outline-none focus:border-[var(--color-brand)] placeholder:text-[var(--color-text-4)] transition-colors"
            />
          </div>
        </Toolbar>
      </div>

      {/* Main content: sidebar + table */}
      <div className="no-drag" style={{ display: 'flex', flex: 1, overflow: 'hidden' }}>
        <Sidebar
          downloads={downloads}
          activeCategory={activeCategory}
          onSelectCategory={setActiveCategory}
        />
        <div style={{ display: 'flex', flexDirection: 'column', flex: 1, backgroundColor: 'var(--color-surface)', overflow: 'hidden', position: 'relative', borderTop: '1px solid var(--color-border)', borderLeft: '1px solid var(--color-border-subtle)' }}>
          <DownloadsTable
            items={filteredDownloads}
            selectedIds={selectedIds}
            activeCategory={activeCategory}
            onSelect={handleSelect}
            onSelectAll={handleSelectAll}
            onDoubleClick={handleDoubleClick}
            onAction={handleGridAction}
          />
        </div>
      </div>

      {/* Status bar */}
      <div className="no-drag" style={{ height: 24, borderTop: '1px solid var(--color-border)', backgroundColor: 'var(--color-surface-raised)', display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 12px', fontSize: 11, color: 'var(--color-text-3)', flexShrink: 0, userSelect: 'none', fontWeight: 500 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span>{downloads.length} downloads</span>
          <span style={{ width: 1, height: 12, backgroundColor: 'var(--color-border)' }} />
          <span>{downloads.filter(d => d.status === 'downloading' || d.status === 'connecting').length} active</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
            <span style={{ fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.08em', fontSize: 9, color: 'var(--color-text-4)' }}>Speed:</span>
            <span style={{ color: 'var(--color-text-1)', fontWeight: 500 }}>
              {(() => {
                const totalSpeed = downloads.reduce((sum, d) => sum + ((d.status === 'downloading' || d.status === 'connecting') ? d.speed_bps || 0 : 0), 0);
                return `${(totalSpeed / (1024 * 1024)).toFixed(1)} MB/s`;
              })()}
            </span>
          </div>
          <span style={{ width: 1, height: 12, backgroundColor: 'var(--color-border)' }} />
          <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <div style={{ width: 8, height: 8, borderRadius: '50%', backgroundColor: isConnected ? 'var(--color-success)' : 'var(--color-error)', boxShadow: isConnected ? '0 0 6px var(--color-success)' : '0 0 6px var(--color-error)', transition: 'all 0.3s ease' }} />
            <span>{isConnected ? 'Connected' : 'Disconnected'}</span>
          </div>
        </div>
      </div>

      {/* Dialogs */}

      {ui.isSettingsModalOpen && (
        <OptionsDialog onClose={() => { ui.setSettingsModalOpen(false); fetchConfig(); }} />
      )}

      {ui.isSchedulerModalOpen && (
        <SchedulerDialog downloads={downloads} onClose={() => ui.setSchedulerModalOpen(false)} />
      )}

      {ui.isDeleteModalOpen && (
        <DeleteDialog
          count={selectedIds.length}
          onClose={() => ui.setDeleteModalOpen(false)}
          onConfirm={executeDeleteSelected}
        />
      )}

      {ui.isRefreshModalOpen && (
        <RefreshUrlDialog
          item={ui.refreshModalItem}
          onClose={() => ui.setRefreshModalOpen(false)}
          onOk={() => { ui.setRefreshModalOpen(false); fetchDownloads(); }}
        />
      )}

      {ui.isGrabberModalOpen && (
        <div className="dialog-overlay">
          <GrabberDialog onClose={() => { ui.setGrabberModalOpen(false); fetchDownloads(); }} />
        </div>
      )}

      <SpiderDialog
        open={ui.isSpiderModalOpen}
        onOpenChange={ui.setSpiderModalOpen}
        onBatchAdd={async (urls) => {
          for (const url of urls) {
            try { await api.add({ url }); } catch (e) { console.error('Failed to batch add URL', url, e); }
          }
          fetchDownloads();
        }}
      />

      {ui.isPropertiesModalOpen && (
        <PropertiesDialog
          item={ui.propertiesModalItem}
          onClose={() => ui.setPropertiesModalOpen(false)}
          onSave={fetchDownloads}
        />
      )}
    </div>
  );
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { getCurrentWindow } from '@tauri-apps/api/window';

export type ThemePreference = 'system' | 'light' | 'dark';
export type ComputedTheme = 'light' | 'dark';

interface ThemeContextType {
  themePref: ThemePreference;
  computedTheme: ComputedTheme;
  setThemePref: (pref: ThemePreference) => void;
}

export const ThemeContext = createContext<ThemeContextType | null>(null);

function getSystemTheme(): ComputedTheme {
  if (typeof window !== 'undefined' && window.matchMedia) {
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  }
  return 'dark'; // Fallback default
}

export const ThemeProvider = ({ children }: { children: React.ReactNode }) => {
  const [themePref, setThemePrefState] = useState<ThemePreference>(() => {
    const stored = localStorage.getItem('vajra-theme-pref') as ThemePreference;
    return stored || 'system';
  });

  const [computedTheme, setComputedTheme] = useState<ComputedTheme>(() => {
    return themePref === 'system' ? getSystemTheme() : themePref;
  });

  // Recompute actual theme whenever preference changes
  useEffect(() => {
    const actual = themePref === 'system' ? getSystemTheme() : themePref;
    setComputedTheme(actual);
  }, [themePref]);

  // Apply computed theme to DOM and Tauri Window
  useEffect(() => {
    const root = document.documentElement;
    // Temporarily disable transition to prevent flash on theme init
    root.style.setProperty('--transition-slow', '0ms');
    if (computedTheme === 'dark') {
      root.classList.add('dark');
      root.classList.remove('light');
      root.style.colorScheme = 'dark';
    } else {
      root.classList.add('light');
      root.classList.remove('dark');
      root.style.colorScheme = 'light';
    }
    // Sync to the key read by the inline script in index.html
    localStorage.setItem('vajra-theme', computedTheme);
    // Re-enable transitions after a brief paint tick
    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        root.style.removeProperty('--transition-slow');
      });
    });

    // Attempt to set native window theme if API is available
    try {
      getCurrentWindow().setTheme(computedTheme);
    } catch (e) {
      console.warn("Failed to set native window theme", e);
    }
  }, [computedTheme]);

  // Listen to OS theme changes if 'system' is selected
  useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');
    const handleChange = (e: MediaQueryListEvent) => {
      if (themePref === 'system') {
        setComputedTheme(e.matches ? 'dark' : 'light');
      }
    };

    // Modern API
    if (mediaQuery.addEventListener) {
      mediaQuery.addEventListener('change', handleChange);
      return () => mediaQuery.removeEventListener('change', handleChange);
    } 
    // Fallback for older WebKit
    else if (mediaQuery.addListener) {
      mediaQuery.addListener(handleChange);
      return () => mediaQuery.removeListener(handleChange);
    }
  }, [themePref]);

  // Listen for storage events to sync themes across multiple WebviewWindows
  useEffect(() => {
    const handleStorage = (e: StorageEvent) => {
      if (e.key === 'vajra-theme-pref' && e.newValue) {
        setThemePrefState(e.newValue as ThemePreference);
      }
    };
    window.addEventListener('storage', handleStorage);
    return () => window.removeEventListener('storage', handleStorage);
  }, []);

  const setThemePref = (pref: ThemePreference) => {
    setThemePrefState(pref);
    localStorage.setItem('vajra-theme-pref', pref);
    // Note: storage events don't fire in the window that triggered them,
    // so we update our own state directly above.
  };

  return (
    <ThemeContext.Provider value={{ themePref, computedTheme, setThemePref }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error("useTheme must be used within a ThemeProvider");
  return context;
};

// Vajra REST API client — connects to vajrad on 127.0.0.1:6277
import { invoke } from '@tauri-apps/api/core';
import {
  AddDownloadRequest,
  DaemonConfig,
  DownloadInfo,
  DownloadList,
  StatsResponse,
  InspectResponse,
  VaultCredentialResponse,
  DaemonEvent,
  AddVaultCredentialRequest,
  PatchDownloadRequest,
  InspectRequest
} from './types';

const PORT = 6277;
const BASE = `http://127.0.0.1:${PORT}/api/v1`;
const HEALTH = `http://127.0.0.1:${PORT}/health`;

async function req<T>(method: string, path: string, body?: any): Promise<T> {
  const opts: RequestInit = { method, headers: {} };
  if (body) {
    (opts.headers as any)['Content-Type'] = 'application/json';
    opts.body = JSON.stringify(body);
  }
  const url = path.startsWith('http') ? path : `${BASE}${path}`;
  const r = await fetch(url, opts);
  if (!r.ok) {
    const text = await r.text().catch(() => r.statusText);
    throw new Error(text || `HTTP ${r.status}`);
  }
  const ct = r.headers.get('content-type') || '';
  if (ct.includes('application/json')) return r.json();
  const text = await r.text();
  try {
    return JSON.parse(text);
  } catch {
    return text as unknown as T;
  }
}

const isMock = window.location.search.includes('mock=true');

export const api = {
  health:  (): Promise<any> => isMock ? Promise.resolve({ status: 'ok' }) : req('GET', HEALTH),
  stats:   (): Promise<StatsResponse> => isMock ? Promise.resolve({ active_count: 1, queued_count: 0, paused_count: 0, complete_today: 0, failed_today: 0, aggregate_speed_bps: 0, aggregate_limit_bps: null, total_downloaded_bytes: 0, daemon_uptime_seconds: 0 }) : req('GET', '/stats'),
  list:    (params: string = ''): Promise<DownloadList>  => isMock ? Promise.resolve({ items: [], total: 0, limit: 100, offset: 0 }) : req('GET', `/downloads${params}`),
  get:     (id: string): Promise<DownloadInfo>         => isMock ? Promise.resolve({} as DownloadInfo) : req('GET', `/downloads/${id}`),
  add:     (body: AddDownloadRequest): Promise<{ id: string, status: string, url: string, filename?: string, created_at: number }> => isMock ? Promise.resolve({ id: 'mock-2', status: 'downloading', url: body.url, filename: body.filename, created_at: Date.now() }) : req('POST', '/downloads', body),
  patch:   (id: string, body: PatchDownloadRequest): Promise<void>   => isMock ? Promise.resolve() : req('PATCH', `/downloads/${id}`, body),
  remove:  (id: string, del?: boolean): Promise<void>    => isMock ? Promise.resolve() : req('DELETE', `/downloads/${id}${del ? '?delete_file=true' : ''}`),
  inspect: (url: string): Promise<InspectResponse>        => isMock ? Promise.resolve({ effective_url: url, filename: 'mock_file.zip', total_bytes: 1024*1024*500, content_type: 'application/zip', accepts_ranges: true, ytdlp_supported: false }) : req('POST', '/inspect', { url }),
  config:  (): Promise<DaemonConfig>           => isMock ? Promise.resolve({} as DaemonConfig) : req('GET', '/config'),
  setConfig: (body: Partial<DaemonConfig>): Promise<void>     => isMock ? Promise.resolve() : req('PATCH', '/config', body),
  getVault: (): Promise<VaultCredentialResponse[]> => isMock ? Promise.resolve([]) : req('GET', '/vault'),
  addVault: (body: AddVaultCredentialRequest): Promise<VaultCredentialResponse> => isMock ? Promise.resolve({ id: 'mock', domain: body.domain, username: body.username, created_at: Date.now() }) : req('POST', '/vault', body),
  deleteVault: (id: string): Promise<void> => isMock ? Promise.resolve() : req('DELETE', `/vault/${id}`),
  openBrowserSetup: async (): Promise<void> => {
    try {
      await invoke('open_browser_setup');
    } catch (err) {
      window.open('http://127.0.0.1:6277/setup', '_blank');
    }
  },
};

// SSE — global event stream
export function connectSSE(onEvent: (event: DaemonEvent) => void, onError: (error: any) => void): () => void {
  if (isMock) {
    const interval = setInterval(() => {
      onEvent({
        event: 'progress',
        download_id: 'mock-1',
        url: 'http://example.com/file.zip',
        filename: 'file.zip',
        total_bytes: 1024*1024*100,
        downloaded_bytes: Math.floor(Math.random() * 1024 * 1024 * 50),
        speed_bps: 2500000 + Math.random() * 500000,
        eta_seconds: 120,
        status: 'downloading',
        resume_supported: true,
        segments: [],
        error: null
      });
    }, 1000);
    return () => clearInterval(interval);
  }

  const es = new EventSource(`${BASE}/events`);

  const handleEvent = (eventName: string) => (e: MessageEvent) => {
    try {
      const data = JSON.parse(e.data);
      // Ensure the "event" property matches the DaemonEvent discriminators
      onEvent({ event: eventName as any, ...data } as DaemonEvent);
    } catch {}
  };

  es.addEventListener('progress', handleEvent('progress'));
  es.addEventListener('state_change', handleEvent('state_change'));
  es.addEventListener('hash_result', handleEvent('hash_result'));
  es.addEventListener('added', handleEvent('added'));
  es.addEventListener('removed', handleEvent('removed'));
  es.addEventListener('intercepted', handleEvent('intercepted'));

  es.onerror = onError;
  return () => es.close();
}

// Formatting helpers
export function fmtBytes(b: number | null | undefined): string {
  if (b == null) return '?';
  const u = ['B','KB','MB','GB','TB'];
  let v = b, i = 0;
  while (v >= 1024 && i < u.length - 1) { v /= 1024; i++; }
  return i === 0 ? `${v.toFixed(0)} ${u[i]}` : `${v.toFixed(1)} ${u[i]}`;
}

export function fmtSpeed(bps: number | null | undefined): string {
  if (bps == null) return '';
  return `${fmtBytes(bps)}/s`;
}

export function fmtEta(secs: number | null | undefined): string {
  if (!secs) return '';
  if (secs < 60) return `${secs}s`;
  if (secs < 3600) return `${Math.floor(secs/60)}m ${secs % 60}s`;
  return `${Math.floor(secs/3600)}h ${Math.floor((secs%3600)/60)}m`;
}

export function fileExt(name: string | null | undefined): string {
  const m = name?.match(/\.([a-z0-9]{1,8})$/i);
  return m ? m[1].toUpperCase() : 'FILE';
}

// Sound effects using the Web Audio API (no external file dependencies)
export const playSound = (type: string) => {
  try {
    const configStr = localStorage.getItem('vajra_sounds_config');
    const config = configStr ? JSON.parse(configStr) : { onComplete: true, onFail: false, onQueueStart: false };

    if (type === 'complete' && !config.onComplete) return;
    if (type === 'fail' && !config.onFail) return;
    if (type === 'queue' && !config.onQueueStart) return;

    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();

    if (type === 'complete') {
      // Play a happy arpeggio: C5, E5, G5, C6
      const notes = [523.25, 659.25, 783.99, 1046.50];
      const duration = 0.12;
      notes.forEach((freq, i) => {
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.connect(gain);
        gain.connect(ctx.destination);

        osc.type = 'sine';
        osc.frequency.setValueAtTime(freq, ctx.currentTime + i * duration);

        gain.gain.setValueAtTime(0.15, ctx.currentTime + i * duration);
        gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + (i + 1.2) * duration);

        osc.start(ctx.currentTime + i * duration);
        osc.stop(ctx.currentTime + (i + 1.5) * duration);
      });
    } else if (type === 'fail') {
      // Play a buzzer sound (dissonant low frequency)
      const osc1 = ctx.createOscillator();
      const osc2 = ctx.createOscillator();
      const gain = ctx.createGain();

      osc1.connect(gain);
      osc2.connect(gain);
      gain.connect(ctx.destination);

      osc1.type = 'sawtooth';
      osc2.type = 'sawtooth';

      osc1.frequency.setValueAtTime(130, ctx.currentTime);
      osc2.frequency.setValueAtTime(135, ctx.currentTime);

      gain.gain.setValueAtTime(0.2, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.4);

      osc1.start();
      osc2.start();
      osc1.stop(ctx.currentTime + 0.4);
      osc2.stop(ctx.currentTime + 0.4);
    } else if (type === 'queue') {
      // Play a short rising blip
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.connect(gain);
      gain.connect(ctx.destination);

      osc.type = 'sine';
      osc.frequency.setValueAtTime(440, ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.15);

      gain.gain.setValueAtTime(0.15, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.15);

      osc.start();
      osc.stop(ctx.currentTime + 0.15);
    }
  } catch (e) {
    console.error("Audio failed to play", e);
  }
}

