      </div>
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';
import { X, Globe, Link, FileDown, FileText, FileImage, FileAudio, FileVideo, Download, AppWindow } from 'lucide-react';
import { api } from '../../api';
import { cn } from '../../utils';

const TYPE_ICONS: Record<string, { icon: any; color: string }> = {
  video:    { icon: FileVideo,  color: 'var(--color-brand)' },
  audio:    { icon: FileAudio,  color: 'var(--color-success)' },
  image:    { icon: FileImage,  color: 'var(--color-error)' },
  document: { icon: FileText,   color: 'var(--color-info)' },
  page:     { icon: AppWindow,  color: 'var(--color-warning)' },
};

interface SpiderResult { url: string; name: string; resource_type: string; }

export function GrabberDialog({ onClose }: { onClose: () => void }) {
  const [url, setUrl]           = useState('');
  const [running, setRunning]   = useState(false);
  const [results, setResults]   = useState<SpiderResult[]>([]);
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [filter, setFilter]     = useState('all');
  const esRef = useRef<EventSource | null>(null);

  useEffect(() => () => { if (esRef.current) esRef.current.close(); }, []);

  function handleStart(e: React.FormEvent) {
    e.preventDefault();
    if (!url.trim()) return;
    if (running) { esRef.current?.close(); setRunning(false); return; }
    setResults([]); setSelected(new Set()); setRunning(true);
    const es = new EventSource(`http://127.0.0.1:6277/api/v1/spider?url=${encodeURIComponent(url)}`);
    esRef.current = es;
    es.onmessage = (ev) => { try { const d = JSON.parse(ev.data); setResults(p => p.some(r => r.url===d.url) ? p : [...p, d]); } catch {} };
    es.onerror = () => { es.close(); setRunning(false); };
  }

  const filtered = results.filter(r => filter === 'all' || r.resource_type === filter);
  const toggleSelect = (u: string) => setSelected(p => { const n = new Set(p); n.has(u) ? n.delete(u) : n.add(u); return n; });
  const selectAll    = () => setSelected(selected.size === filtered.length ? new Set() : new Set(filtered.map(r => r.url)));

  async function downloadSelected() {
    for (const r of results.filter(r => selected.has(r.url))) { try { await api.add({ url: r.url }); } catch {} }
    onClose();
  }

  const tabRow = (items: string[], activeKey: string, setKey: (k: string) => void) => (
    <div className="flex gap-5 px-4 pt-2 shrink-0 drag-region" style={{ borderBottom: '1px solid var(--color-border)', backgroundColor: 'var(--color-surface-raised)' }}>
      {items.map(f => (
        <div key={f} onClick={() => setKey(f)} className="no-drag relative pb-2" style={{
          fontSize: 'var(--text-xs-size)', fontWeight: 700, textTransform: 'capitalize', cursor: 'default',
          color: activeKey === f ? 'var(--color-brand)' : 'var(--color-text-3)',
          transition: 'color var(--transition-fast)',
        }}>
          {f}
          {activeKey === f && <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: 2, backgroundColor: 'var(--color-brand)', borderRadius: 2 }} />}
        </div>
      ))}
    </div>
  );

  return (
    <div className="dialog-overlay" onClick={onClose}>
      <div className="dialog-panel" style={{ width: 780, height: '78vh', maxHeight: 620 }} onClick={e => e.stopPropagation()}>
        {/* Header */}
        <div className="dialog-header">
          <div className="dialog-header-title"><Globe size={16} /> Site Grabber</div>
          <button className="btn-icon" onClick={onClose} title="Close"><X size={15} /></button>
        </div>

        {/* Crawl form */}
        <div style={{ padding: 'var(--sp-3)', borderBottom: '1px solid var(--color-border)', flexShrink: 0 }}>
          <form onSubmit={handleStart} className="flex gap-2">
            <input className="input-field flex-1" placeholder="Root URL to grab resources from…" value={url} onChange={e => setUrl(e.target.value)} disabled={running} />
            <button type="submit" className={running ? 'btn-danger' : 'btn-primary'} style={{ minWidth: 80 }}>
              {running ? 'Stop' : 'Grab'}
            </button>
          </form>
        </div>

        {/* Filter tabs */}
        {results.length > 0 && tabRow(['all','video','audio','image','document','page'], filter, setFilter)}

        {/* Results list */}
        <div className="flex-1 overflow-y-auto" style={{ backgroundColor: 'var(--color-surface)' }}>
          {filtered.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full gap-2" style={{ color: 'var(--color-text-4)' }}>
              {running ? (
                <>
                  <div className="w-6 h-6 rounded-full border-2 animate-spin" style={{ borderColor: 'var(--color-brand)', borderTopColor: 'transparent' }} />
                  <span style={{ fontSize: 'var(--text-sm-size)', fontWeight: 600 }}>Grabbing…</span>
                </>
              ) : (
                <span style={{ fontSize: 'var(--text-sm-size)' }}>No results. Enter a URL and start the grabber.</span>
              )}
            </div>
          ) : (
            <div className="flex flex-col">
              {filtered.map(r => {
                const def = TYPE_ICONS[r.resource_type] || { icon: Link, color: 'var(--color-text-3)' };
                const Icon = def.icon;
                const isSel = selected.has(r.url);
                return (
                  <label key={r.url} className="flex items-center gap-3 px-3 py-2" style={{
                    borderBottom: '1px solid var(--color-border-subtle)', cursor: 'default',
                    backgroundColor: isSel ? 'var(--color-brand-dim)' : 'transparent',
                    transition: 'background-color var(--transition-fast)',
                  }}>
                    <input type="checkbox" checked={isSel} onChange={() => toggleSelect(r.url)} style={{ accentColor: 'var(--color-brand)', width: 13, height: 13, cursor: 'default' }} />
                    <Icon size={14} style={{ color: def.color, flexShrink: 0 }} />
                    <div className="flex-1 min-w-0 flex items-center justify-between gap-4">
                      <span className="truncate" style={{ fontSize: 'var(--text-sm-size)', fontWeight: 600, color: isSel ? 'var(--color-brand)' : 'var(--color-text-1)' }} title={r.name}>{r.name}</span>
                      <span className="truncate" style={{ fontSize: 'var(--text-xs-size)', color: 'var(--color-text-4)', maxWidth: '50%' }} title={r.url}>{r.url}</span>
                    </div>
                  </label>
                );
              })}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="dialog-footer justify-between">
          <span style={{ fontSize: 'var(--text-sm-size)', color: 'var(--color-text-3)', fontWeight: 600 }}>
            {selected.size} / {filtered.length} selected
          </span>
          <div className="flex gap-2">
            <button className="btn-secondary" onClick={selectAll} disabled={filtered.length === 0}>Select All</button>
            <button className="btn-primary flex items-center gap-2" onClick={downloadSelected} disabled={selected.size === 0}>
              <Download size={14} /> Batch Add
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  X, Settings, FileBox, Wifi, HardDriveDownload, 
  Network, Lock, Phone, MonitorPlay, FileCheck2, 
  Globe, Fingerprint, Activity, Server, AlertCircle, 
  Check, Save, Trash2, FolderOpen
} from 'lucide-react';
import { cn } from '../../utils';
import { api } from '../../api';
import { open } from '@tauri-apps/plugin-dialog';
import { useTheme, ThemePreference } from '../../ThemeContext';

export default function OptionsDialog({ onClose }: { onClose: () => void }) {
  const [activeTab, setActiveTab] = useState('General');
  const [config, setConfig] = useState<any>(null);
  const [deletePreference, setDeletePreference] = useState(() => localStorage.getItem('vajra_delete_preference'));
  const [isSaving, setIsSaving] = useState(false);
  
  const { themePref, setThemePref } = useTheme();

  // Site Logins
  const [logins, setLogins] = useState<any[]>([]);

  const [newLoginHost, setNewLoginHost] = useState('');
  const [newLoginUser, setNewLoginUser] = useState('');
  const [newLoginPass, setNewLoginPass] = useState('');

  // Dialup Settings
  const [dialup, setDialup] = useState<any>(() => {
    try {
      const saved = localStorage.getItem('vajra_dialup_settings');
      if (saved) return JSON.parse(saved);
    } catch(e) {}
    return { connectionName: '', username: '', password: '', redialCount: 5 };
  });

  // Sound Config
  const [soundConfig, setSoundConfig] = useState<any>(() => {
    try {
      const saved = localStorage.getItem('vajra_sounds_config');
      if (saved) return JSON.parse(saved);
    } catch(e) {}
    return { onComplete: true, onFail: false, onQueueStart: false };
  });

  useEffect(() => {
    const loadConfig = () => api.config().then(setConfig).catch(e => { console.error("Config load error:", e); setConfig({ _error: e.toString() }); });
    loadConfig();
    (window as any)._retryConfig = loadConfig;
    api.getVault().then(setLogins).catch(console.error);
  }, []);

  useEffect(() => {
    localStorage.setItem('vajra_dialup_settings', JSON.stringify(dialup));
  }, [dialup]);

  useEffect(() => {
    localStorage.setItem('vajra_sounds_config', JSON.stringify(soundConfig));
  }, [soundConfig]);

  const updateConfig = (updates: any) => {
    setConfig((prev: any) => {
      const next = { ...prev, ...updates };
      setIsSaving(true);
      api.setConfig(next)
        .then(() => setTimeout(() => setIsSaving(false), 500))
        .catch(console.error);
      return next;
    });
  };

  const updateProxy = (updates: any) => {
    setConfig((prev: any) => {
      const next = { ...prev, proxy: { ...prev.proxy, ...updates } };
      setIsSaving(true);
      api.setConfig(next)
        .then(() => setTimeout(() => setIsSaving(false), 500))
        .catch(console.error);
      return next;
    });
  };

  const Toggle = ({ active, onClick, label }: { active: boolean; onClick: () => void; label?: string }) => (
    <label className="flex items-center justify-between" style={{ cursor: 'default' }}>
      {label && <span style={{ fontSize: 'var(--text-sm-size)', fontWeight: 500, color: 'var(--color-text-1)' }}>{label}</span>}
      <div
        onClick={e => { e.preventDefault(); onClick(); }}
        style={{
          position: 'relative', display: 'inline-flex', height: 20, width: 36,
          borderRadius: 10, transition: 'background-color var(--transition-normal)',
          backgroundColor: active ? 'var(--color-brand)' : 'var(--color-border)',
          cursor: 'default', flexShrink: 0,
        }}
      >
        <span style={{
          position: 'absolute', top: 2, left: 2, width: 16, height: 16,
          borderRadius: '50%', backgroundColor: 'var(--color-surface)',
          boxShadow: 'var(--shadow-sm)', transition: 'transform var(--transition-normal)',
          transform: active ? 'translateX(16px)' : 'translateX(0)',
        }} />
      </div>
    </label>
  );

  const tabs = [
    { id: 'General', icon: Settings, desc: 'Startup, browser & dialogs' },
    { id: 'File Types', icon: FileBox, desc: 'Auto-downloads & blacklists' },
    { id: 'Connection', icon: Wifi, desc: 'Limits & speed tuning' },
    { id: 'Downloads', icon: HardDriveDownload, desc: 'Directories & actions' },
    { id: 'Automation & Security', icon: Activity, desc: 'Scheduling & AV' },
    { id: 'Proxy / Socks', icon: Network, desc: 'Proxy configuration' },
    { id: 'Site Logins', icon: Lock, desc: 'Saved credentials' },
    { id: 'Dial-up', icon: Phone, desc: 'VPN & Dial-up settings' }
  ];

  const handleBrowseFolder = async (field: string) => {
    try {
      const selected = await open({ directory: true });
      if (selected) {
        updateConfig({ [field]: selected });
      }
    } catch (err) {
      console.error("Folder picker not available", err);
    }
  };

  const handleBrowseFile = async (field: string) => {
    try {
      const selected = await open({ directory: false });
      if (selected) {
        updateConfig({ [field]: selected });
      }
    } catch (err) {
      console.error("File picker not available", err);
    }
  };

  const addLogin = async () => {
    if (newLoginHost.trim() && newLoginUser.trim() && newLoginPass.trim()) {
      try {
        const added = await api.addVault({
          domain: newLoginHost.trim(),
          username: newLoginUser.trim(),
          password: newLoginPass.trim()
        });
        setLogins(prev => [...prev, added].sort((a, b) => a.domain.localeCompare(b.domain)));
        setNewLoginHost('');
        setNewLoginUser('');
        setNewLoginPass('');
      } catch (err) {
        console.error("Failed to add site login", err);
      }
    }
  };

  const removeLogin = async (id: string) => {
    try {
      await api.deleteVault(id);
      setLogins(prev => prev.filter(l => l.id !== id));
    } catch (err) {
      console.error("Failed to remove site login", err);
    }
  };

  // Modern Input Component
  const ConfigInput = ({ label, value, onChange, placeholder, type = "text", icon: Icon }: any) => (
    <div className="flex flex-col gap-1.5 w-full">
      <label className="text-xs font-semibold text-[var(--color-text-2)] uppercase tracking-wider">{label}</label>
      <div className="relative">
        {Icon && <Icon className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--color-text-3)]" size={14} />}
        <input 
          type={type}
          placeholder={placeholder}
          className={cn(
            "w-full bg-[var(--color-surface-elevated)] border border-border/50 rounded-lg px-3 py-2 text-sm text-[var(--color-text-1)]",
            "focus:outline-none focus:ring-2 focus:ring-[var(--color-brand-dim)] focus:border-[var(--color-brand)] transition-all placeholder:text-[var(--color-text-4)]",
            Icon ? "pl-9" : ""
          )}
          value={value}
          onChange={onChange}
        />
      </div>
    </div>
  );

  return (
    <div className="dialog-overlay" onClick={onClose}>
      <div className="dialog-panel" style={{ width: 860, height: 580, maxWidth: '92vw', maxHeight: '90vh', flexDirection: 'column' }} onClick={e => e.stopPropagation()}>
        
        {/* Header */}
        <div className="dialog-header" style={{ padding: '12px 20px' }}>
          <div className="dialog-header-title" style={{ gap: 10 }}>
            <div style={{ backgroundColor: 'var(--color-brand-dim)', padding: 8, borderRadius: 'var(--radius-lg)', color: 'var(--color-brand)', display: 'flex' }}>
              <Settings size={18} />
            </div>
            <div>
              <div style={{ fontWeight: 700, fontSize: 'var(--text-base-size)', color: 'var(--color-text-1)' }}>Settings</div>
              <div style={{ fontSize: 'var(--text-xs-size)', color: 'var(--color-text-3)', marginTop: 2 }}>Configure Vajra's core behavior</div>
            </div>
          </div>
          <div className="flex items-center gap-3">
            {isSaving && (
              <span style={{ fontSize: 'var(--text-xs-size)', color: 'var(--color-brand)', display: 'flex', alignItems: 'center', gap: 4 }}>
                <Activity size={12} className="animate-pulse" /> Saving…

              </span>
            )}
            <button className="btn-icon" onClick={onClose} title="Close"><X size={16} /></button>
          </div>
        </div>
        
        <div className="flex flex-1 overflow-hidden">
          {/* Sidebar nav */}
          <div style={{ width: 220, flexShrink: 0, borderRight: '1px solid var(--color-border)', backgroundColor: 'var(--color-sidebar)', display: 'flex', flexDirection: 'column', padding: '8px 6px', gap: 2, overflowY: 'auto' }}>
            {tabs.map(t => {
              const isActive = activeTab === t.id;
              return (
                <button
                  key={t.id}
                  onClick={() => setActiveTab(t.id)}
                  style={{
                    display: 'flex', alignItems: 'flex-start', gap: 10,
                    width: '100%', textAlign: 'left', padding: '8px 10px',
                    borderRadius: 'var(--radius-lg)', border: 'none', cursor: 'default',
                    backgroundColor: isActive ? 'var(--color-brand-dim)' : 'transparent',
                    position: 'relative', transition: 'background-color var(--transition-fast)',
                  }}
                  onMouseEnter={e => { if (!isActive) (e.currentTarget as HTMLElement).style.backgroundColor = 'var(--color-surface-raised)'; }}
                  onMouseLeave={e => { if (!isActive) (e.currentTarget as HTMLElement).style.backgroundColor = 'transparent'; }}
                >
                  {isActive && (
                    <div style={{ position: 'absolute', left: 0, top: '50%', transform: 'translateY(-50%)', width: 3, height: 22, backgroundColor: 'var(--color-brand)', borderRadius: '0 2px 2px 0' }} />
                  )}
                  <t.icon size={16} style={{ marginTop: 2, color: isActive ? 'var(--color-brand)' : 'var(--color-text-3)', flexShrink: 0 }} />
                  <div>
                    <div style={{ fontWeight: 600, fontSize: 'var(--text-sm-size)', color: isActive ? 'var(--color-brand)' : 'var(--color-text-1)' }}>{t.id}</div>
