          {/* Main Content Area */}
          <div className="flex-1 overflow-y-auto relative" style={{ padding: 'var(--sp-6)', backgroundColor: 'var(--color-surface)' }}>
            {!config ? (
              <div className="absolute inset-0 flex flex-col items-center justify-center text-[var(--color-text-3)] gap-4">
