                          </div>
                          <div className="flex items-center bg-[var(--color-surface-raised)] rounded-lg p-1">
                            {(['system', 'light', 'dark'] as ThemePreference[]).map((mode) => (
                              <button
                                key={mode}
                                onClick={() => setThemePref(mode)}
                                className={cn(
                                  "px-3 py-1.5 rounded-md text-xs font-medium capitalize transition-colors duration-200",
                                  themePref === mode ? "bg-[var(--color-brand)] text-white shadow-sm" : "text-[var(--color-text-3)] hover:text-[var(--color-text-1)]"
                                )}
                              >
                                {mode}
                              </button>
                            ))}
                          </div>
                        </div>
                      </div>
                    </section>

                    <section>
                      <h3 className="text-sm font-bold text-[var(--color-text-1)] mb-4 flex items-center gap-2">
                        <MonitorPlay size={16} style={{ color: "var(--color-brand)" }}/> System Integration
                      </h3>
                      <div className="bg-[var(--color-surface)] border border-border/40 rounded-2xl p-5 shadow-sm flex flex-col gap-6">
                        <div className="flex items-center justify-between">
                          <div className="pr-4">
                            <div className="font-semibold text-sm text-[var(--color-text-1)]">Launch on Startup</div>
                            <div className="text-xs text-[var(--color-text-3)] mt-1">Automatically start Vajra in the background when Windows boots up.</div>
                          </div>
                          <Toggle active={config.auto_start_on_login} onClick={() => updateConfig({ auto_start_on_login: !config.auto_start_on_login })} />
                        </div>
                        <div className="h-px bg-[var(--color-border-subtle)] w-full" />
                        <div className="flex items-center justify-between">
                          <div className="pr-4">
                            <div className="font-semibold text-sm text-[var(--color-text-1)]">Browser Extension Integration</div>
                            <div className="text-xs text-[var(--color-text-3)] mt-1">Captures downloads directly from Chrome, Edge, and Firefox.</div>
                          </div>
                          <button 
                            className="btn-ghost text-xs px-4 py-2 rounded-lg" 
                            onClick={() => api.openBrowserSetup()}
                          >
                            Configure
                          </button>
                        </div>
                        <div className="h-px bg-[var(--color-border-subtle)] w-full" />
                        <div className="flex items-center justify-between">
                          <div className="pr-4">
                            <div className="font-semibold text-sm text-[var(--color-text-1)]">Clipboard Monitoring</div>
                            <div className="text-xs text-[var(--color-text-3)] mt-1">Automatically detect and capture copied URLs.</div>
                          </div>
                          <Toggle active={config.enable_clipboard_monitor !== false} onClick={() => updateConfig({ enable_clipboard_monitor: config.enable_clipboard_monitor === false ? true : false })} />
                        </div>
                      </div>
                    </section>

                    <section>
                      <h3 className="text-sm font-bold text-[var(--color-text-1)] mb-4 flex items-center gap-2">
                        <AlertCircle size={16} style={{ color: "var(--color-brand)" }}/> Confirmation Dialogs
                      </h3>
                      <div className="bg-[var(--color-surface)] border border-border/40 rounded-2xl p-5 shadow-sm flex flex-col gap-6">
                        <div className="flex items-center justify-between">
                          <div className="pr-4">
                            <div className="font-semibold text-sm text-[var(--color-text-1)]">Confirm before deleting</div>
                            <div className="text-xs text-[var(--color-text-3)] mt-1">Show a safety prompt when deleting files or clearing history.</div>
                          </div>
                          <Toggle active={!deletePreference} onClick={() => {
                            if (deletePreference) {
                              localStorage.removeItem('vajra_delete_preference');
                              setDeletePreference(null);
                            } else {
                              localStorage.setItem('vajra_delete_preference', 'list_only');
                              setDeletePreference('list_only');
                            }
                          }} />
                        </div>
                      </div>
                    </section>

                    <section>
                      <h3 className="text-sm font-bold text-[var(--color-text-1)] mb-4 flex items-center gap-2">
                        <Activity size={16} style={{ color: "var(--color-brand)" }}/> Interception Hotkeys
                      </h3>
                      <div className="bg-[var(--color-surface)] border border-border/40 rounded-2xl p-5 shadow-sm flex flex-col gap-4">
                        <div className="flex items-center justify-between bg-[var(--color-surface-raised)] p-3 rounded-xl border border-border/30">
                          <span className="text-sm text-[var(--color-text-2)]">Hold <kbd className=" bg-[var(--color-surface-elevated)] border border-border/60 px-2 py-0.5 rounded shadow-sm font-bold text-[var(--color-text-1)] mx-1">Alt</kbd> during click</span>
