                <FieldLabel>Max Connections</FieldLabel>
                <select className="select-field" value={maxConnections} onChange={e => setMaxConnections(e.target.value)}>
                  <option value="1">1 Thread (Safest)</option>
                  <option value="4">4 Threads</option>
                  <option value="8">8 Threads (Recommended)</option>
                  <option value="16">16 Threads (Aggressive)</option>
                  <option value="32">32 Threads (Extreme)</option>
                </select>
              </div>
              <div className="form-group">
                <FieldLabel>Speed Limit (KB/s)</FieldLabel>
                <input type="number" min="0" className="input-field" placeholder="0 = Unlimited" value={speedLimit} onChange={e => setSpeedLimit(e.target.value)} />
              </div>
            </div>
          </div>

          {/* Status Details */}
          <div className="flex flex-col gap-3 mt-1">
            <SectionHead icon={Activity} label="Status Details" />

            {/* Status banner */}
            <div className="card-subtle flex items-center justify-between" style={{ padding: 'var(--sp-3) var(--sp-4)' }}>
              <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full" style={{ backgroundColor: statusColor, animation: item.status === 'downloading' ? 'pulse 2s infinite' : 'none' }} />
                <span style={{ fontSize: 'var(--text-xs-size)', color: 'var(--color-text-3)', fontWeight: 700 }}>Current Status</span>
              </div>
              <span style={{ fontWeight: 700, fontSize: 'var(--text-sm-size)', color: statusColor, textTransform: 'uppercase', letterSpacing: '0.1em' }}>
                {item.status}
              </span>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <StatCard icon={Download} label="Total Size"       value={item.total_bytes ? fmtBytes(item.total_bytes) : '—'} />
              <StatCard icon={Save}     label="Downloaded"       value={fmtBytes(item.bytes_done || 0)} />
              <StatCard icon={Calendar} label="Date Added"       value={item.created_at ? new Date(item.created_at * 1000).toLocaleDateString() : '—'} />
              <StatCard icon={Clock}    label="Date Completed"   value={item.completed_at ? new Date(item.completed_at * 1000).toLocaleDateString() : '—'} />
            </div>

            <div className="card-subtle flex items-center justify-between" style={{ padding: 'var(--sp-3) var(--sp-4)' }}>
              <span style={{ fontSize: 'var(--text-sm-size)', color: 'var(--color-text-3)', fontWeight: 500 }}>Server Resume Support</span>
              {item.resume_supported !== false ? (
                <span className="tag tag-success">Supported</span>
              ) : (
                <span className="tag tag-error">Not Supported</span>
              )}
            </div>

            {item.hash_result && (
              <div className="card-subtle" style={{ padding: 'var(--sp-3) var(--sp-4)', borderColor: 'var(--color-brand-dim)', backgroundColor: 'var(--color-brand-dim)' }}>
                <div className="flex items-center gap-2 mb-2" style={{ fontSize: 'var(--text-xs-size)', fontWeight: 700, color: 'var(--color-brand)' }}>
                  <ShieldCheck size={12} /> Integrity Verification
                </div>
                <div className="flex items-center justify-between">
                  <span style={{ fontSize: 'var(--text-xs-size)', color: 'var(--color-text-3)' }}>
                    {item.hash_result.algorithm}
                  </span>
                  <span className={item.hash_result.matched ? 'tag tag-success' : 'tag tag-error'}>
                    {item.hash_result.matched ? 'Matched' : 'Mismatch'}
                  </span>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Footer */}
        <div className="dialog-footer">
          <button className="btn-primary" onClick={onClose}>Done</button>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { X, Link as LinkIcon, AlertTriangle, ShieldCheck } from 'lucide-react';
import { api, fmtBytes, DownloadItem } from '../../api';

interface InspectData {
  total_bytes?: number;
  accepts_ranges?: boolean;
  content_type?: string;
}

export default function RefreshUrlDialog({
  item, onClose, onOk,
}: {
  item: DownloadItem;
  onClose: () => void;
  onOk: () => void;
}) {
  const [url, setUrl]             = useState(item?.url || '');
  const [inspectState, setIS]     = useState<'idle'|'loading'|'success'|'error'>('idle');
  const [inspectData, setID]      = useState<InspectData | null>(null);
  const [errorMsg, setErrorMsg]   = useState('');

  useEffect(() => {
    if (!url.trim() || !url.startsWith('http') || url.trim() === item?.url) {
      setIS('idle'); setID(null); return;
    }
    const t = setTimeout(async () => {
      setIS('loading'); setErrorMsg('');
      try { const r = await api.inspect(url.trim()); setID(r); setIS('success'); }
      catch (e: any) { setIS('error'); setErrorMsg(e.message || 'Could not inspect URL'); }
    }, 800);
    return () => clearTimeout(t);
  }, [url, item]);

  const handleApply = async () => {
    if (!url.trim()) return;
    try {
      await api.patch(item.id, { url: url.trim() });
      await api.patch(item.id, { action: 'resume' });
      onOk();
    } catch (e: any) { alert('Failed to refresh address: ' + e.message); }
  };

  const sizeMismatch = inspectData?.total_bytes && item?.total_bytes && item.total_bytes !== inspectData.total_bytes;

  return (
    <div className="dialog-overlay" onClick={onClose}>
      <div className="dialog-panel" style={{ width: 480 }} onClick={e => e.stopPropagation()}>
        {/* Header */}
        <div className="dialog-header">
          <div className="dialog-header-title">
            <LinkIcon size={16} />
            Refresh Download Address
          </div>
          <button className="btn-icon" onClick={onClose} title="Close"><X size={15} /></button>
        </div>

        {/* Body */}
        <div className="dialog-body">
          <p style={{ fontSize: 'var(--text-sm-size)', color: 'var(--color-text-3)', lineHeight: 1.6 }}>
            Paste a new download URL to update an expired link. Vajra will resume from where it left off.
          </p>

          {/* File name info */}
          <div className="card-subtle" style={{ padding: 'var(--sp-2) var(--sp-3)' }}>
            <span className="section-title">File</span>
            <p style={{ fontWeight: 600, fontSize: 'var(--text-base-size)', color: 'var(--color-text-1)', marginTop: 2 }}>
              {item?.filename || 'Unknown File'}
            </p>
          </div>

          {/* New URL */}
          <div className="form-group">
            <div className="flex items-center justify-between">
              <span className="form-label">New URL</span>
              {inspectState === 'loading' && <span style={{ fontSize: 'var(--text-xs-size)', color: 'var(--color-info)' }}>Inspecting…</span>}
              {inspectState === 'error'   && <span style={{ fontSize: 'var(--text-xs-size)', color: 'var(--color-error)' }}>Inspect failed</span>}
            </div>
            <input
              type="text"
              className="input-field"
              value={url}
              onChange={e => setUrl(e.target.value)}
              placeholder="Paste new https:// link"
              autoFocus
            />
          </div>

          {/* Inspect results */}
          {inspectState === 'success' && inspectData && (
            <div className="card-subtle" style={{ padding: 'var(--sp-3)' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 'var(--text-sm-size)' }}>
                <span style={{ color: 'var(--color-text-3)' }}>Remote Size</span>
                <span style={{ fontWeight: 600, color: 'var(--color-text-1)' }}>
                  {inspectData.total_bytes ? fmtBytes(inspectData.total_bytes) : '—'}
                  {sizeMismatch && <span style={{ color: 'var(--color-error)', marginLeft: 6 }}>(Mismatch!)</span>}
                </span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: 6, fontSize: 'var(--text-sm-size)' }}>
                <span style={{ color: 'var(--color-text-3)' }}>Resume Support</span>
                <span style={{ fontWeight: 600, color: inspectData.accepts_ranges ? 'var(--color-success)' : 'var(--color-warning)' }}>
                  {inspectData.accepts_ranges ? 'Yes' : 'No'}
                </span>
              </div>
              {sizeMismatch && (
                <div style={{ display: 'flex', alignItems: 'flex-start', gap: 6, marginTop: 8, paddingTop: 8, borderTop: '1px solid var(--color-border-subtle)', fontSize: 'var(--text-xs-size)', color: 'var(--color-warning)', fontWeight: 600 }}>
                  <AlertTriangle size={12} style={{ flexShrink: 0, marginTop: 1 }} />
                  File size mismatch — resuming may fail or corrupt the file.
                </div>
              )}
            </div>
          )}

          {inspectState === 'error' && (
            <div style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 'var(--text-xs-size)', color: 'var(--color-error)', fontWeight: 600 }}>
              <AlertTriangle size={12} />
              {errorMsg}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="dialog-footer">
          <button className="btn-secondary" onClick={onClose}>Cancel</button>
          <button
            className="btn-primary flex items-center gap-2"
            onClick={handleApply}
            disabled={!url.trim() || url.trim() === item?.url}
          >
            <ShieldCheck size={14} />
            Apply & Resume
          </button>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
