import React, { useState, useRef, useEffect } from 'react';
import {
  File, FileArchive, FileAudio, FileVideo, Settings as SettingsIcon,
  Clock, CheckCircle2, AlertCircle, Pause, Play, RefreshCw, Trash2,
  Info, Eye, Activity, ArrowUp, ArrowDown
} from 'lucide-react';
import { cn } from '../utils';
import { fmtBytes, fmtSpeed, fmtEta } from '../api';
import { DownloadItem } from '../api';

const COLUMN_DEFAULTS = {
  checkbox:  { label: 'Checkbox',       visible: true,  width: 32  },
  filename:  { label: 'File Name',      visible: true,  width: 240 },
  progress:  { label: 'Progress',       visible: true,  width: 160 },
  size:      { label: 'Size',           visible: true,  width: 80  },
  status:    { label: 'Status',         visible: true,  width: 95  },
  time:      { label: 'Time Left',      visible: true,  width: 90  },
  speed:     { label: 'Transfer Rate',  visible: true,  width: 100 },
  resume:    { label: 'Resume',         visible: true,  width: 65  },
  category:  { label: 'Category',       visible: false, width: 90  },
  savePath:  { label: 'Save Path',      visible: false, width: 160 },
  url:       { label: 'URL',            visible: false, width: 200 },
  added:     { label: 'Added',          visible: true,  width: 130 },
};

/* ---- Helpers ---- */
const getCategoryLabel = (item: any): string => {
  const name = item.filename || item.file_name || item.url || '';
  const ext  = name.split('.').pop()?.toLowerCase();
  if (['zip','rar','7z','tar','gz','bz2','xz','zst','iso','img'].includes(ext)) return 'Compressed';
  if (['pdf','doc','docx','xls','xlsx','ppt','pptx','txt','epub'].includes(ext))  return 'Documents';
  if (['mp3','wav','flac','aac','ogg','m4a','wma','opus'].includes(ext))          return 'Music';
  if (['exe','msi','apk','dmg','pkg','deb','rpm'].includes(ext))                  return 'Programs';
  if (['mp4','mkv','avi','mov','wmv','flv','webm','ts'].includes(ext))            return 'Video';
  return 'General';
};

const getFileIcon = (filename: string = '') => {
  const ext = filename.split('.').pop()?.toLowerCase();
  if (ext && ['zip','rar','7z','tar','gz'].includes(ext)) return FileArchive;
  if (ext && ['mp3','wav','flac'].includes(ext))          return FileAudio;
  if (ext && ['mp4','mkv','avi','mov'].includes(ext))     return FileVideo;
  if (ext && ['exe','msi','apk','dmg'].includes(ext))     return SettingsIcon;
  return File;
};

const STATUS_TAG: Record<string, string> = {
  completed:   'tag tag-success',
  complete:    'tag tag-success',
  downloading: 'tag tag-info',
  connecting:  'tag tag-info',
  paused:      'tag tag-warning',
  failed:      'tag tag-error',
  error:       'tag tag-error',
};

export default function DownloadsTable({
  items, selectedIds = [], activeCategory, onSelect, onSelectAll, onDoubleClick, onAction,
}: {
  items: DownloadItem[];
  selectedIds?: string[];
  activeCategory: string;
  onSelect: (id: string, shiftKey: boolean, ctrlKey: boolean) => void;
  onSelectAll: (ids: string[]) => void;
  onDoubleClick: (item: DownloadItem) => void;
  onAction: (item: DownloadItem, action: string) => void;
}) {
  const [columns, setColumns] = useState(() => {
    try {
      const saved = localStorage.getItem('vajra_table_columns_v3');
      if (saved) return JSON.parse(saved);
    } catch {}
    return COLUMN_DEFAULTS;
  });
  const [sortCol, setSortCol]     = useState('filename');
  const [sortDesc, setSortDesc]   = useState(false);
  const [contextMenu, setContextMenu] = useState<{x: number; y: number; item: DownloadItem} | null>(null);
  const [headerMenu, setHeaderMenu]   = useState<{x: number; y: number} | null>(null);

  useEffect(() => {
    localStorage.setItem('vajra_table_columns_v3', JSON.stringify(columns));
  }, [columns]);

  // Close menus on any click
  useEffect(() => {
    const close = () => { setContextMenu(null); setHeaderMenu(null); };
    document.addEventListener('click', close);
    document.addEventListener('contextmenu', close);
    return () => { document.removeEventListener('click', close); document.removeEventListener('contextmenu', close); };
  }, []);

  const handleContextMenu = (e: React.MouseEvent, item: DownloadItem) => {
    e.preventDefault(); e.stopPropagation();
    onSelect(item.id, false, false);
    const mW = 180, mH = 220;
    const x = Math.min(e.clientX, window.innerWidth  - mW - 8);
    const y = Math.min(e.clientY, window.innerHeight - mH - 8);
    setContextMenu({ x, y, item });
    setHeaderMenu(null);
  };

  const handleHeaderContextMenu = (e: React.MouseEvent) => {
    e.preventDefault(); e.stopPropagation();
    const mW = 180, mH = 320;
    const x = Math.min(e.clientX, window.innerWidth  - mW - 8);
    const y = Math.min(e.clientY, window.innerHeight - mH - 8);
    setHeaderMenu({ x, y });
    setContextMenu(null);
  };

  const handleSort = (col: string) => {
    if (sortCol === col) setSortDesc(!sortDesc);
    else { setSortCol(col); setSortDesc(false); }
  };

  /* ---- Filtering + Sorting ---- */
  const filteredItems = (() => {
    let out = [...items];
    if      (activeCategory === 'Completed')  out = out.filter(d => d.status === 'completed' || d.status === 'complete');
    else if (activeCategory === 'Unfinished') out = out.filter(d => ['downloading','connecting','paused','failed','error'].includes(d.status));
    else if (activeCategory === 'Grabber')    out = [];
    else if (['Compressed','Documents','Music','Programs','Video'].includes(activeCategory))
      out = out.filter(d => getCategoryLabel(d) === activeCategory);

    out.sort((a, b) => {
      let va: any, vb: any;
      switch (sortCol) {
        case 'filename': va = (a.filename||a.file_name||a.url||'').toLowerCase(); vb = (b.filename||b.file_name||b.url||'').toLowerCase(); break;
        case 'size':     va = a.total_bytes||0;   vb = b.total_bytes||0;   break;
        case 'status':   va = a.status||'';       vb = b.status||'';       break;
        case 'time':     va = a.eta_seconds||Infinity; vb = b.eta_seconds||Infinity; break;
        case 'speed':    va = a.speed_bps||0;     vb = b.speed_bps||0;     break;
        case 'added':    va = a.created_at||0;    vb = b.created_at||0;    break;
        case 'category': va = getCategoryLabel(a); vb = getCategoryLabel(b); break;
        case 'savePath': va = (a.output_path||'').toLowerCase(); vb = (b.output_path||'').toLowerCase(); break;
        case 'url':      va = (a.url||'').toLowerCase(); vb = (b.url||'').toLowerCase(); break;
        default: return 0;
      }
      if (va < vb) return sortDesc ? 1 : -1;
      if (va > vb) return sortDesc ? -1 : 1;
      return 0;
    });
    return out;
  })();

  const allSelected = filteredItems.length > 0 && selectedIds.length === filteredItems.length;

  /* ---- Resizable Header ---- */
  const ResizableHeader = ({ col, label }: { col: string; label: string }) => {
    const isResizing = useRef(false);
    const startX     = useRef(0);
    const startW     = useRef(0);

    const onMouseDown = (e: React.MouseEvent) => {
      e.preventDefault(); e.stopPropagation();
      isResizing.current = true;
      startX.current     = e.clientX;
      startW.current     = columns[col].width;
      const onMove = (mv: MouseEvent) => {
        if (!isResizing.current) return;
        const diff = mv.clientX - startX.current;
        setColumns((p: any) => ({ ...p, [col]: { ...p[col], width: Math.max(40, startW.current + diff) } }));
      };
      const onUp = () => { isResizing.current = false; document.removeEventListener('mousemove', onMove); document.removeEventListener('mouseup', onUp); };
      document.addEventListener('mousemove', onMove);
      document.addEventListener('mouseup', onUp);
    };

    if (!columns[col]?.visible) return null;

    return (
      <th
        style={{ width: columns[col].width, minWidth: columns[col].width, maxWidth: columns[col].width }}
        className="table-th relative"
        onContextMenu={handleHeaderContextMenu}
      >
        <div
          className="flex items-center gap-1 w-full overflow-hidden"
          onClick={() => handleSort(col)}
          style={{ cursor: 'default' }}
        >
          <span className="truncate">{label}</span>
          {sortCol === col && (
            sortDesc
              ? <ArrowDown size={10} style={{ color: 'var(--color-brand)', flexShrink: 0 }} />
              : <ArrowUp   size={10} style={{ color: 'var(--color-brand)', flexShrink: 0 }} />
          )}
        </div>
        {/* Resize handle */}
        <div
          className="absolute right-0 top-0 bottom-0 w-1 cursor-col-resize z-20"
          style={{ ':hover': { backgroundColor: 'var(--color-brand)' } } as any}
          onMouseEnter={e => (e.currentTarget.style.backgroundColor = 'var(--color-brand)')}
          onMouseLeave={e => (e.currentTarget.style.backgroundColor = 'transparent')}
          onMouseDown={onMouseDown}
        />
      </th>
    );
  };

  /* ---- Context menus ---- */
  const CtxItem = ({
    icon: Icon, label, action, danger = false, disabled = false,
    item,
  }: {
    icon: React.ElementType; label: string; action: string; danger?: boolean; disabled?: boolean; item: DownloadItem;
  }) => (
    <button
      disabled={disabled}
      onClick={e => { e.stopPropagation(); setContextMenu(null); onAction(item, action); }}
      className={cn('context-menu-item w-full text-left', danger && 'danger')}
      style={disabled ? { opacity: 0.38, cursor: 'not-allowed' } : {}}
    >
      <Icon size={14} style={{ flexShrink: 0 }} />
      {label}
    </button>
  );

  return (
    <div className="flex-1 overflow-auto" style={{ backgroundColor: 'var(--color-surface)' }}>
      <table className="w-full text-left border-collapse table-fixed relative" aria-label="Downloads List">
        <thead>
          <tr>
            {/* Checkbox column */}
            <th
              style={{ width: columns.checkbox.width, minWidth: columns.checkbox.width }}
              className="table-th text-center sticky top-0 z-10"
              onContextMenu={handleHeaderContextMenu}
            >
              <input
                type="checkbox"
                checked={allSelected}
                aria-label="Select all downloads"
                style={{ accentColor: 'var(--color-brand)', cursor: 'default', width: 13, height: 13 }}
                onChange={e => onSelectAll(e.target.checked ? filteredItems.map(i => i.id) : [])}
              />
            </th>
            <ResizableHeader col="filename"  label="File Name"     />
            <ResizableHeader col="progress"  label="Progress"      />
            <ResizableHeader col="size"      label="Size"          />
            <ResizableHeader col="status"    label="Status"        />
            <ResizableHeader col="time"      label="Time Left"     />
            <ResizableHeader col="speed"     label="Transfer Rate" />
            <ResizableHeader col="resume"    label="Resume"        />
            <ResizableHeader col="category"  label="Category"      />
            <ResizableHeader col="savePath"  label="Save Path"     />
            <ResizableHeader col="url"       label="URL"           />
            <ResizableHeader col="added"     label="Added"         />
          </tr>
        </thead>
        <tbody>
          {filteredItems.map(item => {
            const isSelected = selectedIds.includes(item.id);
            const Icon = getFileIcon(item.filename || item.file_name || '');
            const pct = item.progress_pct ?? 0;
            const isComplete  = item.status === 'completed' || item.status === 'complete';
            const isActive    = item.status === 'downloading' || item.status === 'connecting';
            const isFailed    = item.status === 'failed' || item.status === 'error';
            const statusLabel = item.status.charAt(0).toUpperCase() + item.status.slice(1);
            const tagClass    = STATUS_TAG[item.status] || 'tag tag-neutral';

            return (
              <tr
                key={item.id}
                onClick={e => { e.stopPropagation(); onSelect(item.id, e.shiftKey, e.metaKey || e.ctrlKey); }}
                onDoubleClick={() => onDoubleClick(item)}
                onContextMenu={e => handleContextMenu(e, item)}
                className={cn('table-row', isSelected && 'selected')}
                style={{ fontSize: 'var(--text-sm-size)', height: '34px' }}
                aria-selected={isSelected}
                role="row"
              >
                {/* Checkbox */}
                <td
                  className="text-center px-2"
                  style={{ borderRight: '1px solid var(--color-border-subtle)' }}
                  onClick={e => { e.stopPropagation(); onSelect(item.id, false, true); }}
                >
                  <input
                    type="checkbox"
                    checked={isSelected}
                    readOnly
                    aria-label={`Select ${item.filename || item.url}`}
                    style={{ accentColor: 'var(--color-brand)', cursor: 'default', width: 13, height: 13, pointerEvents: 'none' }}
                  />
                </td>

                {/* Filename */}
                {columns.filename?.visible && (
                  <td className="px-2 truncate" style={{ maxWidth: columns.filename.width, borderRight: '1px solid var(--color-border-subtle)' }}>
                    <div className="flex items-center gap-1.5 truncate">
                      <Icon
                        size={14}
                        strokeWidth={1.5}
                        style={{ color: isComplete ? 'var(--color-success)' : 'var(--color-brand)', flexShrink: 0 }}
                      />
                      <span className="truncate font-medium" style={{ color: 'var(--color-text-1)' }}>
                        {item.filename || item.file_name || item.url}
                      </span>
                    </div>
                  </td>
                )}

                {/* Progress */}
                {columns.progress?.visible && (
                  <td className="px-2" style={{ maxWidth: columns.progress.width, borderRight: '1px solid var(--color-border-subtle)' }}>
                    <div className="flex items-center gap-2">
                      <div className="progress-track flex-1">
                        <div
                          className={cn('progress-fill', isComplete && 'success', isFailed && 'error')}
                          style={{ width: `${pct}%` }}
                        />
                      </div>
                      <span style={{ fontSize: 'var(--text-xs-size)', fontWeight: 600, color: 'var(--color-text-3)', width: 30, textAlign: 'right' }}>
                        {pct.toFixed(0)}%
                      </span>
                    </div>
                  </td>
                )}

                {/* Size */}
                {columns.size?.visible && (
                  <td className="px-2 truncate" style={{ maxWidth: columns.size.width, color: 'var(--color-text-2)', borderRight: '1px solid var(--color-border-subtle)' }}>
                    {item.total_bytes ? fmtBytes(item.total_bytes) : '—'}
                  </td>
                )}

                {/* Status */}
                {columns.status?.visible && (
                  <td className="px-2" style={{ maxWidth: columns.status.width, borderRight: '1px solid var(--color-border-subtle)' }}>
                    <span className={tagClass}>{statusLabel}</span>
                  </td>
                )}

                {/* Time Left */}
                {columns.time?.visible && (
                  <td className="px-2 truncate" style={{ maxWidth: columns.time.width, color: 'var(--color-text-3)', borderRight: '1px solid var(--color-border-subtle)' }}>
                    {isActive && item.eta_seconds != null ? fmtEta(item.eta_seconds) : ''}
                  </td>
                )}

                {/* Speed */}
                {columns.speed?.visible && (
                  <td className="px-2 truncate" style={{ maxWidth: columns.speed.width, color: 'var(--color-text-2)', borderRight: '1px solid var(--color-border-subtle)' }}>
                    {isActive && item.speed_bps ? fmtSpeed(item.speed_bps) : ''}
                  </td>
                )}

                {/* Resume */}
                {columns.resume?.visible && (
                  <td className="px-2 text-center" style={{ maxWidth: columns.resume.width, borderRight: '1px solid var(--color-border-subtle)' }}>
                    <span className={item.resume_supported !== false ? 'tag tag-success' : 'tag tag-error'}>
                      {item.resume_supported !== false ? 'Yes' : 'No'}
                    </span>
                  </td>
                )}

                {/* Category */}
                {columns.category?.visible && (
                  <td className="px-2 truncate" style={{ maxWidth: columns.category.width, color: 'var(--color-text-3)', borderRight: '1px solid var(--color-border-subtle)' }}>
                    {getCategoryLabel(item)}
                  </td>
                )}

                {/* Save Path */}
                {columns.savePath?.visible && (
                  <td className="px-2 truncate" style={{ maxWidth: columns.savePath.width, color: 'var(--color-text-3)', fontFamily: 'var(--font-mono)', borderRight: '1px solid var(--color-border-subtle)', fontSize: 'var(--text-xs-size)' }}>
                    {item.output_path || ''}
                  </td>
                )}

                {/* URL */}
                {columns.url?.visible && (
                  <td className="px-2 truncate" style={{ maxWidth: columns.url.width, color: 'var(--color-text-4)', borderRight: '1px solid var(--color-border-subtle)', fontSize: 'var(--text-xs-size)' }}>
                    {item.url || ''}
                  </td>
                )}

                {/* Added */}
                {columns.added?.visible && (
                  <td className="px-2 truncate" style={{ maxWidth: columns.added.width, color: 'var(--color-text-4)', fontSize: 'var(--text-xs-size)' }}>
                    {item.created_at ? new Date(item.created_at * 1000).toLocaleString() : ''}
                  </td>
                )}
              </tr>
            );
          })}
        </tbody>
      </table>

      {/* Empty state */}
      {filteredItems.length === 0 && (
        <div className="flex flex-col items-center justify-center h-40 gap-2" style={{ color: 'var(--color-text-4)' }}>
          <File size={28} strokeWidth={1} />
          <p style={{ fontSize: 'var(--text-sm-size)', fontWeight: 500 }}>No downloads in this view</p>
        </div>
      )}

      {/* Header column-picker context menu */}
      {headerMenu && (
        <div
          className="context-menu"
          style={{ top: headerMenu.y, left: headerMenu.x }}
          onClick={e => e.stopPropagation()}
        >
          <div className="px-3 pb-2 pt-1 flex items-center gap-1.5" style={{ borderBottom: '1px solid var(--color-border-subtle)', marginBottom: 4 }}>
            <Eye size={12} style={{ color: 'var(--color-brand)' }} />
            <span style={{ fontSize: 'var(--text-xs-size)', fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.06em', color: 'var(--color-text-3)' }}>
              Columns
            </span>
          </div>
          {Object.keys(columns).map(key => {
            if (key === 'checkbox' || key === 'filename') return null;
            return (
              <label key={key} className="context-menu-item justify-between cursor-default">
                <span>{columns[key].label}</span>
                <input
                  type="checkbox"
                  checked={columns[key].visible}
                  style={{ accentColor: 'var(--color-brand)', cursor: 'default', width: 13, height: 13 }}
                  onChange={() => setColumns((p: any) => ({ ...p, [key]: { ...p[key], visible: !p[key].visible } }))}
                />
              </label>
            );
          })}
        </div>
      )}

      {/* Row context menu */}
      {contextMenu && (
        <div
          className="context-menu"
          style={{ top: contextMenu.y, left: contextMenu.x }}
          onClick={e => e.stopPropagation()}
        >
          {contextMenu.item.status === 'downloading' || contextMenu.item.status === 'connecting' ? (
            <CtxItem icon={Pause} label="Pause" action="pause" item={contextMenu.item} />
          ) : (
            <CtxItem icon={Play}  label="Resume" action="resume" item={contextMenu.item}
              disabled={contextMenu.item.status === 'completed' || contextMenu.item.status === 'complete'} />
          )}
          {contextMenu.item.status !== 'completed' && contextMenu.item.status !== 'complete' && (
            <CtxItem icon={Activity} label="Show Progress" action="show_progress" item={contextMenu.item} />
          )}
          <div className="context-menu-separator" />
          <CtxItem icon={RefreshCw} label="Refresh Link" action="refresh_url" item={contextMenu.item}
            disabled={contextMenu.item.status === 'completed' || contextMenu.item.status === 'complete'} />
          <div className="context-menu-separator" />
          <CtxItem icon={Trash2} label="Delete"     action="delete"     item={contextMenu.item} danger />
          <CtxItem icon={Info}   label="Properties" action="properties" item={contextMenu.item} />
        </div>
      )}
    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { getCurrentWindow } from '@tauri-apps/api/window';
import { invoke } from '@tauri-apps/api/core';
import { useTheme } from '../ThemeContext';
import { Moon, Sun, Monitor, Zap } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { cn } from '../utils';

export default function MenuBar({
  onAdd, onOptions, onPauseAll, onResumeAll,
}: {
  onAdd: () => void;
  onOptions: () => void;
  onPauseAll: () => void;
  onResumeAll: () => void;
}) {
  const { t } = useTranslation();
  const [activeMenu, setActiveMenu] = useState<string | null>(null);
  const menuRef = useRef<HTMLDivElement>(null);
  const { themePref, setThemePref } = useTheme();

  const handleThemeToggle = () => {
    if (themePref === 'system') setThemePref('light');
    else if (themePref === 'light') setThemePref('dark');
    else setThemePref('system');
  };

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setActiveMenu(null);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleMenuClick = (name: string) =>
    setActiveMenu(activeMenu === name ? null : name);

  const handleAction = (action: string) => {
    setActiveMenu(null);
    if      (action === 'add')       onAdd();
    else if (action === 'options')   onOptions();
    else if (action === 'pauseAll')  onPauseAll();
    else if (action === 'resumeAll') onResumeAll();
    else if (action === 'exit')      invoke('cmd_quit_app').catch(console.error);
  };

  /* ---- Styles (semantic variables, no hardcoded colors) ---- */
  const menuBtnStyle = (name: string) => ({
    padding: '3px 8px',
    fontSize: 'var(--text-xs-size)',
    fontWeight: '600',
    letterSpacing: '0.01em',
    borderRadius: 'var(--radius-sm)',
    cursor: 'default',
    userSelect: 'none' as const,
    color: activeMenu === name ? 'var(--color-brand)' : 'var(--color-text-3)',
    backgroundColor: activeMenu === name ? 'var(--color-brand-dim)' : 'transparent',
    transition: 'background-color var(--transition-fast), color var(--transition-fast)',
    WebkitAppRegion: 'no-drag' as any,
  });

  const dropdownStyle: React.CSSProperties = {
    position: 'absolute',
    top: 'calc(100% + 4px)',
    left: 0,
    minWidth: '180px',
    padding: '4px 0',
    backgroundColor: 'var(--color-surface)',
    border: '1px solid var(--color-border)',
    borderRadius: 'var(--radius-lg)',
    boxShadow: 'var(--shadow-lg)',
    zIndex: 50,
    animation: 'slideDialog var(--transition-fast) ease',
  };

  const itemStyle: React.CSSProperties = {
    padding: '6px 14px',
    fontSize: 'var(--text-sm-size)',
    color: 'var(--color-text-1)',
    cursor: 'default',
    transition: 'background-color var(--transition-fast)',
  };

  const MenuItem = ({ label, action }: { label: string; action: string }) => (
    <div
      style={itemStyle}
      onMouseEnter={e => (e.currentTarget.style.backgroundColor = 'var(--color-surface-raised)')}
      onMouseLeave={e => (e.currentTarget.style.backgroundColor = 'transparent')}
      onClick={() => handleAction(action)}
    >
      {label}
    </div>
  );

  const MenuDivider = () => (
    <div style={{ height: '1px', backgroundColor: 'var(--color-border-subtle)', margin: '3px 0' }} />
  );

  const themeIcon = themePref === 'dark' ? Moon : themePref === 'light' ? Sun : Monitor;
  const ThemeIcon = themeIcon;

  return (
    <div
      ref={menuRef}
      className="flex items-center justify-between w-full h-full drag-region select-none"
      style={{ color: 'var(--color-text-1)' }}
    >
      {/* Left: Brand + Menu Items */}
      <div className="flex items-center gap-1">
        {/* Brand */}
        <div
          className="flex items-center gap-1 mr-3 pl-1 no-drag"
          style={{
            fontSize: 'var(--text-xs-size)',
            fontWeight: '800',
            letterSpacing: '0.12em',
            color: 'var(--color-brand)',
          }}
        >
          <Zap size={12} strokeWidth={2.5} />
          VAJRA
        </div>

        {/* File menu */}
        <div className="relative">
          <div style={menuBtnStyle('File')} onClick={() => handleMenuClick('File')}>
            {t('File')}
          </div>
          {activeMenu === 'File' && (
            <div style={dropdownStyle}>
              <MenuItem label={t('Add New Download')} action="add" />
              <MenuItem label={t('Add Batch Download')} action="batch" />
              <MenuDivider />
              <MenuItem label={t('Exit Application')} action="exit" />
            </div>
          )}
        </div>

        {/* Actions menu */}
        <div className="relative">
          <div style={menuBtnStyle('Actions')} onClick={() => handleMenuClick('Actions')}>
            {t('Actions')}
          </div>
          {activeMenu === 'Actions' && (
            <div style={dropdownStyle}>
              <MenuItem label={t('Pause All active')}   action="pauseAll" />
              <MenuItem label={t('Resume All paused')}  action="resumeAll" />
              <MenuDivider />
              <MenuItem label={t('Settings & Options')} action="options" />
            </div>
          )}
        </div>

        {/* Help menu */}
        <div className="relative">
          <div style={menuBtnStyle('Help')} onClick={() => handleMenuClick('Help')}>
            {t('Help')}
          </div>
          {activeMenu === 'Help' && (
            <div style={dropdownStyle}>
              <MenuItem label={t('Help Documentation')} action="help" />
              <MenuItem label={t('About Vajra')}        action="about" />
            </div>
          )}
        </div>
      </div>

      {/* Right: Theme Toggle */}
      <div className="flex items-center gap-1 no-drag pr-2">
        <button
          onClick={handleThemeToggle}
          title={`Theme: ${themePref}`}
          className="btn-icon"
          style={{ width: '24px', height: '24px' }}
        >
          <ThemeIcon size={13} />
        </button>
      </div>
    </div>
  );
}

import React from 'react';
import { useTranslation } from 'react-i18next';
import {
  Plus, Play, Pause, Trash2, Settings, Calendar,
  StopCircle, CheckSquare, Globe, Network, HelpCircle, Activity, FileText
} from 'lucide-react';
import { cn } from '../utils';

// Icon color map — uses CSS variables for semantic meaning, not raw Tailwind colors
const ICON_COLORS: Record<string, string> = {
  add:        'var(--color-success)',
  resume:     'var(--color-success)',
  pause:      'var(--color-warning)',
  stop:       'var(--color-error)',
  progress:   'var(--color-info)',
  properties: 'var(--color-brand)',
  delete:     'var(--color-error)',
  clear:      'var(--color-text-3)',
  settings:   'var(--color-info)',
  scheduler:  'var(--color-brand)',
  grabber:    'var(--color-success)',
  spider:     'var(--color-info)',
  help:       'var(--color-text-4)',
};

const ActionButton = ({
  icon: Icon,
  label,
  onClick,
  disabled = false,
  colorKey = 'help',
}: {
  icon: React.ElementType;
  label: string;
  onClick: () => void;
  disabled?: boolean;
  colorKey?: string;
}) => {
  const iconColor = ICON_COLORS[colorKey] ?? 'var(--color-text-3)';

  return (
    <button
      onClick={onClick}
      disabled={disabled}
      title={label}
      className={cn('toolbar-btn', !disabled && 'group')}
    >
      <Icon
        size={18}
        strokeWidth={1.5}
        style={{ color: disabled ? 'var(--color-text-4)' : iconColor }}
        className="transition-transform duration-150 group-hover:-translate-y-px"
      />
      <span className="toolbar-btn-label">{label}</span>
    </button>
  );
};

const Divider = () => (
  <div className="w-px h-8 mx-1 shrink-0" style={{ backgroundColor: 'var(--color-border)' }} />
);

export default function Toolbar({
  selectedIds = [],
  onAdd,
  onResumeSelected,
  onPauseSelected,
  onStopAll,
  onDeleteSelected,
  onDeleteCompleted,
  onOptions,
  onScheduler,
  onGrabber,
  onSpider,
  onHelp,
  canResume,
  canPause,
  canStopAll,
  canDelete,
  canDeleteCompleted = false,
  onShowProgress,
  canShowProgress,
  isSelectedCompleted = false,
  children,
}: {
  selectedIds?: string[];
  onAdd: () => void;
  onResumeSelected: () => void;
  onPauseSelected: () => void;
  onStopAll: () => void;
  onDeleteSelected: () => void;
  onDeleteCompleted: () => void;
  onOptions: () => void;
  onScheduler: () => void;
  onGrabber: () => void;
  onSpider: () => void;
  onHelp: () => void;
  canResume: boolean;
  canPause: boolean;
  canStopAll: boolean;
  canDelete: boolean;
  canDeleteCompleted?: boolean;
  onShowProgress: () => void;
  canShowProgress: boolean;
  isSelectedCompleted?: boolean;
  children?: React.ReactNode;
}) {
  const { t } = useTranslation();

  return (
    <div
      className="flex items-center gap-1 px-2 py-1 shrink-0 select-none overflow-x-auto overflow-y-hidden w-full z-10"
      style={{
        backgroundColor: 'var(--color-surface-raised)',
        borderBottom: '1px solid var(--color-border)',
        minHeight: '58px',
      }}
      role="toolbar"
      aria-label={t('toolbar.aria_label', 'Application Toolbar')}
    >
      {/* Group 1: New Tasks */}
      <ActionButton icon={Plus}        label={t('toolbar.add_url', 'Add URL')}  onClick={onAdd}             colorKey="add" />
      <Divider />

      {/* Group 2: Playback Controls */}
      <ActionButton icon={Play}        label={t('toolbar.resume', 'Resume')}    onClick={onResumeSelected}  disabled={!canResume}      colorKey="resume" />
      <ActionButton icon={Pause}       label={t('toolbar.pause', 'Pause')}     onClick={onPauseSelected}   disabled={!canPause}       colorKey="pause" />
      <ActionButton icon={StopCircle}  label={t('toolbar.stop_all', 'Stop All')}  onClick={onStopAll}         disabled={!canStopAll}     colorKey="stop" />
      <ActionButton
        icon={isSelectedCompleted ? FileText : Activity}
        label={isSelectedCompleted ? t('toolbar.properties', 'Properties') : t('toolbar.progress', 'Progress')}
        onClick={onShowProgress}
        disabled={!canShowProgress}
        colorKey={isSelectedCompleted ? 'properties' : 'progress'}
      />
      <Divider />

      {/* Group 3: Delete */}
      <ActionButton icon={Trash2}      label={t('toolbar.delete', 'Delete')}    onClick={onDeleteSelected}  disabled={!canDelete}          colorKey="delete" />
      <ActionButton icon={CheckSquare} label={t('toolbar.clear_completed', 'Clear Completed')}     onClick={onDeleteCompleted} disabled={!canDeleteCompleted}  colorKey="clear" />
      <Divider />

      {/* Group 4: Advanced Tools */}
      <ActionButton icon={Settings}    label={t('toolbar.settings', 'Settings')}  onClick={onOptions}   colorKey="settings" />
      <ActionButton icon={Calendar}    label={t('toolbar.scheduler', 'Scheduler')} onClick={onScheduler} colorKey="scheduler" />
      <ActionButton icon={Globe}       label={t('toolbar.grabber', 'Grabber')}   onClick={onGrabber}   colorKey="grabber" />
      <ActionButton icon={Network}     label={t('toolbar.spider', 'Spider')}    onClick={onSpider}    colorKey="spider" />
      <Divider />

      {/* Group 5: Extra Space / Help */}
      <div className="ml-auto flex items-center pr-2 gap-1">
        {children}
        <ActionButton icon={HelpCircle} label={t('toolbar.help', 'Help')} onClick={onHelp} colorKey="help" />
      </div>
    </div>
  );
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import AddUrlWindow from './windows/AddUrlWindow';
import DownloadCompleteWindow from './windows/DownloadCompleteWindow';
import ProgressWindow from './windows/ProgressWindow';
import { ThemeProvider } from './ThemeContext';
// @ts-ignore
import './index.css';
import './i18n';

import { DownloadProgress } from './types';

import { ErrorBoundary } from './components/ErrorBoundary';

const params = new URLSearchParams(window.location.search);
const windowType = params.get('window');

let RootComponent = <App />;
if (windowType === 'addUrl') {
  RootComponent = <AddUrlWindow initialUrl={params.get('url') || ''} initialFilename={params.get('filename') || ''} />;
} else if (windowType === 'downloadComplete') {
  RootComponent = <DownloadCompleteWindow downloadId={params.get('id')} />;
} else if (windowType === 'progress') {
  RootComponent = <ProgressWindow downloadId={params.get('id') || ''} />;
}

ReactDOM.createRoot(document.getElementById('root') as HTMLElement).render(
  <React.StrictMode>
    <ErrorBoundary>
      <ThemeProvider>
        {RootComponent}
      </ThemeProvider>
    </ErrorBoundary>
  </React.StrictMode>
);

// Prevent native web behaviors to make the app feel like a "hard program"
document.addEventListener('contextmenu', (e) => {
  // Allow right click ONLY on input fields
  const target = e.target as HTMLElement;
  if (target.tagName !== 'INPUT' && target.tagName !== 'TEXTAREA') {
    e.preventDefault();
  }
});

document.addEventListener('dragstart', (e) => {
  if ((e.target as HTMLElement).closest('[draggable="true"]')) {
    return;
  }
  e.preventDefault();
});
document.addEventListener('drop', (e) => e.preventDefault());
document.addEventListener('dragover', (e) => e.preventDefault());

import { create } from 'zustand';
import { DaemonConfig } from '../types';
import { api } from '../api';

interface ConfigStore {
  config: DaemonConfig | null;
  loading: boolean;
  error: string | null;

  // Actions
  fetchConfig: () => Promise<void>;
  updateConfig: (updates: Partial<DaemonConfig>) => Promise<void>;
}

export const useConfigStore = create<ConfigStore>((set, get) => ({
  config: null,
  loading: false,
  error: null,

  fetchConfig: async () => {
    set({ loading: true, error: null });
    try {
      const config = await api.config();
      set({ config, loading: false });
    } catch (err: any) {
      set({ error: err.message || 'Failed to fetch config', loading: false });
    }
  },

  updateConfig: async (updates) => {
    set({ loading: true, error: null });
    try {
      await api.setConfig(updates);
      // refetch to ensure we have the latest merged config from server
      await get().fetchConfig();
    } catch (err: any) {
      set({ error: err.message || 'Failed to update config', loading: false });
    }
  }
}));

import { create } from 'zustand';
import { DownloadInfo, DownloadStatus } from '../types';
import { api } from '../api';

interface DownloadStore {
  downloads: Record<string, DownloadInfo>;
  selectedIds: Set<string>;
  sortBy: keyof DownloadInfo | '';
  sortDirection: 'asc' | 'desc';
  filters: {
    status?: DownloadStatus[];
    category?: string;
    search?: string;
  };

  // Actions
  addOrUpdateDownload: (download: DownloadInfo) => void;
  removeDownload: (id: string) => void;
  setDownloads: (downloads: DownloadInfo[]) => void;

  // Selection
  selectDownload: (id: string, multiSelect?: boolean) => void;
  clearSelection: () => void;
  selectAll: () => void;

  // Filtering and Sorting
  setSortBy: (field: keyof DownloadInfo) => void;
  setFilters: (filters: Partial<DownloadStore['filters']>) => void;

  // Computed (getters)
  getSortedAndFilteredDownloads: () => DownloadInfo[];
}

export const useDownloadStore = create<DownloadStore>((set, get) => ({
  downloads: {},
  selectedIds: new Set(),
  sortBy: 'created_at',
  sortDirection: 'desc',
  filters: {},

  addOrUpdateDownload: (download) => set((state) => ({
    downloads: {
      ...state.downloads,
      [download.id]: {
        ...(state.downloads[download.id] || {}),
        ...download,
      }
    }
  })),

  removeDownload: (id) => set((state) => {
    const newDownloads = { ...state.downloads };
    delete newDownloads[id];

    const newSelected = new Set(state.selectedIds);
    newSelected.delete(id);

    return {
      downloads: newDownloads,
      selectedIds: newSelected,
    };
  }),

  setDownloads: (downloadsList) => set(() => {
    const newDownloads: Record<string, DownloadInfo> = {};
    for (const d of downloadsList) {
      newDownloads[d.id] = d;
    }
    return { downloads: newDownloads };
  }),

  selectDownload: (id, multiSelect = false) => set((state) => {
    const newSelected = multiSelect 
      ? new Set(state.selectedIds)
      : new Set<string>();

    if (newSelected.has(id)) {
      newSelected.delete(id);
    } else {
      newSelected.add(id);
    }

    return { selectedIds: newSelected };
  }),

  clearSelection: () => set({ selectedIds: new Set() }),

  selectAll: () => set((state) => ({
    selectedIds: new Set(Object.keys(state.downloads)),
  })),

  setSortBy: (field) => set((state) => ({
    sortBy: field,
    sortDirection: state.sortBy === field && state.sortDirection === 'desc' 
      ? 'asc' 
      : 'desc',
  })),

  setFilters: (filters) => set((state) => ({
    filters: { ...state.filters, ...filters },
  })),

  getSortedAndFilteredDownloads: () => {
    const { downloads, sortBy, sortDirection, filters } = get();
    let arr = Object.values(downloads);

    // Apply filters
    if (filters.status && filters.status.length > 0) {
      arr = arr.filter(d => filters.status!.includes(d.status));
    }
    if (filters.search) {
      const s = filters.search.toLowerCase();
      arr = arr.filter(d => 
        d.filename.toLowerCase().includes(s) || 
        d.url.toLowerCase().includes(s)
      );
    }

    // Apply sort
    if (sortBy) {
      arr.sort((a, b) => {
        const valA = a[sortBy];
        const valB = b[sortBy];

        if (typeof valA === 'string' && typeof valB === 'string') {
          return sortDirection === 'asc' 
            ? valA.localeCompare(valB) 
            : valB.localeCompare(valA);
        }

        if (typeof valA === 'number' && typeof valB === 'number') {
          return sortDirection === 'asc' ? valA - valB : valB - valA;
        }

        // Handle nulls/undefined gracefully
        if (valA === valB) return 0;
        if (valA == null) return sortDirection === 'asc' ? -1 : 1;
        if (valB == null) return sortDirection === 'asc' ? 1 : -1;

        return 0;
      });
    }

    return arr;
  }
}));

// Setup SSE listener
export function initDownloadStoreSSE() {
  api.connectSSE((e) => {
    const store = useDownloadStore.getState();
    switch (e.event) {
      case 'progress':
      case 'state_change':
      case 'added': {
        // We might not have the full object, fetch if not existing, or update existing.
        // For simplicity, we can fetch from api if it's new, otherwise apply partial progress
        if (!store.downloads[e.download_id || e.id]) {
          api.get(e.download_id || e.id).then(d => {
            if (d) store.addOrUpdateDownload(d);
          }).catch(() => {});
        } else {
          // It's an update
          store.addOrUpdateDownload({
            ...store.downloads[e.download_id || e.id],
            // map event fields to DownloadInfo fields
            ...(e.event === 'progress' && {
              bytes_done: e.downloaded_bytes,
              speed_bps: e.speed_bps,
              eta_seconds: e.eta_seconds,
              total_bytes: e.total_bytes,
              status: e.status,
              segments: e.segments,
              error: e.error
            }),
            ...(e.event === 'state_change' && {
              status: e.status,
              output_path: e.output_path || store.downloads[e.id].output_path,
              error: e.error
            }),
            ...(e.event === 'added' && {
               url: e.url,
               filename: e.filename
            })
          } as any);
        }
        break;
      }
      case 'removed': {
        store.removeDownload(e.id);
        break;
      }
    }
  }, (err) => {
    console.error('SSE Error:', err);
  });
}

