import React, { useState, useEffect } from 'react';
import { getCurrentWindow } from '@tauri-apps/api/window';
import { X, Lock, Link as LinkIcon, Settings2, Folder, HardDrive, Hash, Search, List, AlertTriangle } from 'lucide-react';
import { cn } from '../utils';
import { api, fmtBytes } from '../api';
import { useTranslation } from 'react-i18next';

export default function AddUrlWindow({ initialUrl = '', initialFilename = '' }: { initialUrl?: string, initialFilename?: string }) {
  const { t } = useTranslation();
  const [url, setUrl] = useState(initialUrl);
  const [useAuth, setUseAuth] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [speedLimitKb, setSpeedLimitKb] = useState('');
  const [outputDir, setOutputDir] = useState('');
  const [expectedHash, setExpectedHash] = useState('');
  const [autoExtract, setAutoExtract] = useState(false);
  const [postProcessingScript, setPostProcessingScript] = useState('');
  const [startLater, setStartLater] = useState(false);

  const [inspectState, setInspectState] = useState('idle');
  const [inspectData, setInspectData] = useState<any>(null);
  const [filename, setFilename] = useState(initialFilename);
  const [downloads, setDownloads] = useState<any[]>([]);
  const [showDuplicatePrompt, setShowDuplicatePrompt] = useState(false);

  useEffect(() => {
    const setupListener = async () => {
      const { listen } = await import('@tauri-apps/api/event');
      return listen('update-add-url', (e: any) => {
        if (e.payload?.url) setUrl(e.payload.url);
        if (e.payload?.filename) setFilename(e.payload.filename);
      });
    };
    
    let unlisten: () => void;
    setupListener().then(f => unlisten = f).catch(console.error);
    
    return () => {
      if (unlisten) unlisten();
    };
  }, []);

  useEffect(() => {
    // Fetch downloads to check for duplicates
    api.list().then(res => setDownloads(res.items || [])).catch(console.error);
    api.config().catch(console.error);
    // Focus the window on launch so user can interact immediately
    getCurrentWindow().setFocus().catch(console.error);
  }, []);

  // Auto-fill credentials from Site Logins matching url domain
  useEffect(() => {
    if (!url.trim()) return;
    try {
      const parsedUrl = new URL(url.trim());
      const host = parsedUrl.hostname.toLowerCase();
      
      const savedLoginsStr = localStorage.getItem('vajra_site_logins');
      if (savedLoginsStr) {
        const savedLogins = JSON.parse(savedLoginsStr);
        const match = savedLogins.find((item: any) => {
          const itemHost = item.host.toLowerCase();
          return host === itemHost || host.endsWith('.' + itemHost);
        });
        
        if (match) {
          setUseAuth(true);
          setUsername(match.user);
          setPassword(match.pass);
          setShowAdvanced(true);
        }
      }
    } catch (e) {
      // Ignore URL parsing errors while typing
    }
  }, [url]);

  useEffect(() => {
    if (!url.trim() || !url.startsWith('http')) {
      setInspectState('idle');
      setInspectData(null);
      setFilename('');
      return;
    }
    
    try {
      let urlFile = url.split('/').pop() || 'download';
      urlFile = urlFile.split('?')[0].split('#')[0];
      if (urlFile) setFilename(decodeURIComponent(urlFile));
    } catch (e) {}
    
    const timer = setTimeout(async () => {
      setInspectState('loading');
      try {
        const res = await api.inspect(url.trim());
        setInspectData(res);
        if (res.filename) setFilename(res.filename);
        setInspectState('success');
      } catch (e) {
        setInspectState('error');
      }
    }, 800);

    return () => clearTimeout(timer);
  }, [url]);

  const handleClose = () => {
    getCurrentWindow().close().catch(console.error);
  };

  const urlLines = url.split('\n').map(s => s.trim()).filter(Boolean);
  const isBatch = urlLines.length > 1;

  const submitDownload = async (forceDuplicate: boolean = false) => {
    for (const singleUrl of urlLines) {
      let currentFilename = filename.trim();
      if (!currentFilename && !isBatch) {
        let urlFile = singleUrl.split('/').pop() || 'download';
        urlFile = urlFile.split('?')[0].split('#')[0];
        try { currentFilename = decodeURIComponent(urlFile); } catch(e) { currentFilename = urlFile; }
        if (!currentFilename) currentFilename = 'download';
      }

      if (forceDuplicate && !isBatch) {
        const parts = currentFilename.split('.');
        if (parts.length > 1) {
            const ext = parts.pop();
            currentFilename = `${parts.join('.')} (1).${ext}`;
        } else {
            currentFilename = `${currentFilename} (1)`;
        }
      }

      const payload = {
        url: singleUrl,
        filename: currentFilename || undefined,
        output_dir: outputDir.trim() || undefined,
        expected_hash: isBatch ? undefined : (expectedHash.trim() || undefined),
        auto_extract: autoExtract,
        post_processing_script: postProcessingScript.trim() || undefined,
        speed_limit_bps: speedLimitKb ? parseInt(speedLimitKb, 10) * 1024 : 0,
      };

      if (useAuth && username && password) {
        const token = btoa(`${username}:${password}`);
        (payload as any).headers = { 'Authorization': `Basic ${token}` };
      }

      try {
        const added = await api.add(payload);
        if (startLater) {
          await api.patch(added.id, { action: 'pause' });
        } else if (!isBatch) {
          try {
            const { emit } = await import('@tauri-apps/api/event');
            await emit('open-progress-window', added.id);
          } catch (e) {
            console.error("Failed to emit open-progress-window from AddUrlWindow", e);
          }
        }
      } catch (err: any) {
        alert(`Error adding download for ${singleUrl}: ` + err.message);
      }
    }
    handleClose();
  };

  const handleOk = async () => {
    if (url.trim()) {
      if (isDuplicate) {
        setShowDuplicatePrompt(true);
        return;
      }
      submitDownload(false);
    }
  };

  const handleBrowse = async () => {
    try {
      const { open } = await import('@tauri-apps/plugin-dialog');
      const selected = await open({ directory: true });
      if (selected) {
        setOutputDir(selected as string);
      }
    } catch (err) {
      console.error("Folder picker not available", err);
      alert("Please type the path manually.");
    }
  };

  const isDuplicate = url && downloads.some(d => d.url === url);

  /* Shared inline style shortcuts */
  const S = {
    surface:    'var(--color-surface)',
    raised:     'var(--color-surface-raised)',
    elevated:   'var(--color-surface-elevated)',
    border:     'var(--color-border)',
    borderSub:  'var(--color-border-subtle)',
    t1: 'var(--color-text-1)', t2: 'var(--color-text-2)', t3: 'var(--color-text-3)', t4: 'var(--color-text-4)',
    brand: 'var(--color-brand)', brandDim: 'var(--color-brand-dim)',
    warning: 'var(--color-warning)', warningDim: 'var(--color-warning-dim)',
    error: 'var(--color-error)', success: 'var(--color-success)',
  } as const;

  const card = (extra?: React.CSSProperties): React.CSSProperties => ({
    backgroundColor: S.raised, border: `1px solid ${S.border}`,
    borderRadius: 'var(--radius-lg)', padding: 10, ...extra,
  });

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', overflow: 'hidden', fontFamily: 'var(--font-sans)', backgroundColor: S.surface, color: S.t1, userSelect: 'none' }}>

      {/* Title bar */}
      <div className="drag-region" style={{ height: 36, display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 12px', borderBottom: `1px solid ${S.border}`, backgroundColor: S.raised, flexShrink: 0 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 'var(--text-xs-size)', fontWeight: 600, color: S.t2 }}>
          <HardDrive size={14} style={{ color: S.brand }} />
          {t('add_url.title', 'Add New Download')}
        </div>
        <button className="btn-icon no-drag" onClick={handleClose} style={{ width: 28, height: 28 }} title="Close">
          <X size={14} />
        </button>
      </div>

      {/* Scrollable body */}
      <div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 8, padding: 8 }}>

        {/* URL input */}
        <div style={card()}>
          <label style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', fontSize: 'var(--text-xs-size)', fontWeight: 600, color: S.t2, marginBottom: 6 }}>
            <span style={{ display: 'flex', alignItems: 'center', gap: 4 }}><LinkIcon size={12} /> Target URL</span>
            {inspectState === 'loading' && <span style={{ color: S.brand, display: 'flex', alignItems: 'center', gap: 4, fontSize: 'var(--text-xs-size)' }}><Search size={11} /> Inspecting…</span>}
            {inspectState === 'error'   && <span style={{ color: S.error, fontSize: 'var(--text-xs-size)' }}>HEAD request failed</span>}
          </label>
          <textarea
            className="textarea-field"
            style={{ minHeight: 48, resize: 'vertical', fontSize: 'var(--text-sm-size)' }}
            value={url}
            onChange={e => setUrl(e.target.value)}
            placeholder={t('add_url.url_placeholder', 'https://…\nPaste multiple URLs on separate lines for batch downloading.')}
            autoFocus
          />
          {isBatch ? (
            <div style={{ marginTop: 6, display: 'flex', gap: 12, fontSize: 'var(--text-xs-size)', color: S.brand, backgroundColor: S.brandDim, padding: '6px 10px', borderRadius: 'var(--radius-md)', border: `1px solid ${S.brand}` }}>
              <span style={{ fontWeight: 600 }}>Batch Download Detected</span><span>{urlLines.length} URLs</span>
            </div>
          ) : (
            inspectState === 'success' && inspectData && (
              <div style={{ marginTop: 6, display: 'flex', gap: 12, fontSize: 'var(--text-xs-size)', color: S.t3, backgroundColor: S.elevated, padding: '6px 10px', borderRadius: 'var(--radius-md)', border: `1px solid ${S.borderSub}` }}>
                <span><b style={{ color: S.t1 }}>SIZE:</b> {inspectData.total_bytes ? fmtBytes(inspectData.total_bytes) : 'N/A'}</span>
                <span><b style={{ color: S.t1 }}>TYPE:</b> {inspectData.content_type || 'Unknown'}</span>
                <span style={{ color: inspectData.accepts_ranges ? S.success : S.error }}><b style={{ color: S.t1 }}>RESUME:</b> {inspectData.accepts_ranges ? 'YES' : 'NO'}</span>
              </div>
            )
          )}
          {isDuplicate && (
            <div style={{ marginTop: 6, fontSize: 'var(--text-xs-size)', fontWeight: 600, color: S.warning, backgroundColor: S.warningDim, padding: '6px 10px', borderRadius: 'var(--radius-md)', border: `1px solid ${S.warning}` }}>
              âš  Warning: This URL is already in your download list.
            </div>
          )}
        </div>

        {/* Save As / Directory */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8, flexShrink: 0 }}>
          <div style={card()}>
            <label style={{ display: 'block', fontSize: 'var(--text-xs-size)', fontWeight: 600, color: S.t2, marginBottom: 5 }}>Save As</label>
            <input type="text" className="input-field" style={isBatch ? { opacity: 0.5, cursor: 'not-allowed' } : {}}
              value={filename} onChange={e => setFilename(e.target.value)}
              placeholder={isBatch ? 'Auto-detect (Batch)' : 'Auto-detect'} disabled={isBatch} />
          </div>
          <div style={card()}>
            <label style={{ display: 'block', fontSize: 'var(--text-xs-size)', fontWeight: 600, color: S.t2, marginBottom: 5 }}>Save Location</label>
            <div style={{ display: 'flex', gap: 4 }}>
              <input type="text" className="input-field" style={{ flex: 1 }} value={outputDir} onChange={e => setOutputDir(e.target.value)} placeholder="Default Directory" />
              <button className="btn-secondary" style={{ padding: '0 10px', flexShrink: 0 }} onClick={handleBrowse} title="Browse"><Folder size={14} /></button>
            </div>
          </div>
        </div>

        {/* Speed / Hash */}
        <div style={{ ...card(), display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
          <div className="form-group">
            <label className="form-label">Speed Limit (KB/s)</label>
            <input type="number" className="input-field" value={speedLimitKb} onChange={e => setSpeedLimitKb(e.target.value)} placeholder="0 = Max" />
          </div>
          <div className="form-group">
            <label className="form-label">Verify Hash</label>
            <input type="text" className="input-field" style={isBatch ? { opacity: 0.5, cursor: 'not-allowed' } : {}}
              value={expectedHash} onChange={e => setExpectedHash(e.target.value)}
              placeholder={isBatch ? 'Disabled in batch' : 'sha256:â€¦'} disabled={isBatch} />
          </div>
        </div>

        {/* Toggles */}
        <div style={{ ...card(), display: 'flex', flexWrap: 'wrap', gap: 16, alignItems: 'center' }}>
          {[
            { label: 'HTTP Auth',           state: useAuth,     set: setUseAuth },
            { label: 'Start Paused',        state: startLater,  set: setStartLater },
            { label: 'Auto-Extract Archive',state: autoExtract, set: setAutoExtract },
          ].map(({ label, state, set }) => (
            <label key={label} style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 'var(--text-xs-size)', color: S.t1, cursor: 'default' }}>
              <input type="checkbox" checked={state} onChange={e => set(e.target.checked)} style={{ accentColor: S.brand, width: 13, height: 13, cursor: 'default' }} />
              {label}
            </label>
          ))}
        </div>

        {/* Auth credentials */}
        {useAuth && (
          <div style={{ ...card(), display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
            <div className="form-group">
              <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: 4 }}><Lock size={11} /> Username</label>
              <input type="text" className="input-field" value={username} onChange={e => setUsername(e.target.value)} placeholder="Username" autoComplete="username" />
            </div>
            <div className="form-group">
              <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: 4 }}><Lock size={11} /> Password</label>
              <input type="password" className="input-field" value={password} onChange={e => setPassword(e.target.value)} placeholder="Password" autoComplete="current-password" />
            </div>
          </div>
        )}

        {/* Post-processing */}
        <div style={card()}>
          <label className="form-label" style={{ display: 'flex', alignItems: 'center', gap: 4, marginBottom: 5 }}><List size={11} style={{ color: S.brand }} /> Post-Processing Script (.bat, .ps1)</label>
          <input type="text" className="input-field" value={postProcessingScript} onChange={e => setPostProcessingScript(e.target.value)} placeholder="C:\Scripts\on_complete.ps1" />
        </div>

      </div>

      {/* Footer */}
      <div style={{ padding: '8px 12px', borderTop: `1px solid ${S.border}`, backgroundColor: S.raised, display: 'flex', justifyContent: 'flex-end', gap: 6, flexShrink: 0 }}>
        <button className="btn-secondary" onClick={handleClose}>Cancel</button>
        <button className="btn-primary flex items-center gap-2" onClick={handleOk} disabled={urlLines.length === 0}>
          <HardDrive size={14} /> {isBatch ? `Add ${urlLines.length} Tasks` : t('add_url.add_button', 'Add Download')}
        </button>
      </div>

      {/* Duplicate modal */}
      {showDuplicatePrompt && (
        <div style={{ position: 'absolute', inset: 0, backgroundColor: 'rgba(0,0,0,0.72)', zIndex: 50, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 16, backdropFilter: 'blur(4px)' }}>
          <div style={{ backgroundColor: S.surface, border: `1px solid ${S.warning}`, borderRadius: 'var(--radius-xl)', padding: 20, maxWidth: 340, width: '100%', display: 'flex', flexDirection: 'column', gap: 12, boxShadow: 'var(--shadow-xl)' }}>
            <h3 style={{ display: 'flex', alignItems: 'center', gap: 8, fontWeight: 600, fontSize: 'var(--text-md-size)', color: S.warning, margin: 0 }}>
              <AlertTriangle size={16} /> Duplicate Download
            </h3>
            <p style={{ fontSize: 'var(--text-sm-size)', color: S.t1, lineHeight: 1.6, margin: 0 }}>
              This URL is already in your download list. Download it again as a new file?
            </p>
            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 8 }}>
              <button className="btn-secondary" onClick={() => setShowDuplicatePrompt(false)}>Cancel</button>
              <button
                style={{ display: 'inline-flex', alignItems: 'center', gap: 6, fontFamily: 'var(--font-sans)', fontSize: 'var(--text-base-size)', fontWeight: 500, padding: '0 12px', height: 30, borderRadius: 'var(--radius-md)', cursor: 'default', border: `1px solid ${S.warning}`, backgroundColor: S.warningDim, color: S.warning }}
                onClick={() => { setShowDuplicatePrompt(false); submitDownload(true); }}
              >
                Download Anyway
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { getCurrentWindow } from '@tauri-apps/api/window';
import { invoke } from '@tauri-apps/api/core';
import { CheckCircle2, FolderOpen, Play, X, Copy, Check, File, FileArchive, FileAudio, FileVideo, Settings as SettingsIcon } from 'lucide-react';
import { api, fmtBytes } from '../api';

const getFileIcon = (filename = '') => {
  const ext = filename.split('.').pop()?.toLowerCase();
  if (['zip','rar','7z','tar','gz'].includes(ext as any)) return FileArchive;
  if (['mp3','wav','flac','aac','ogg','m4a'].includes(ext as any)) return FileAudio;
  if (['mp4','mkv','avi','mov','webm','wmv'].includes(ext as any)) return FileVideo;
  if (['exe','msi','apk','dmg','bat'].includes(ext as any)) return SettingsIcon;
  return File;
};

const InfoCard = ({ label, children }: { label: string; children: React.ReactNode }) => (
  <div className="card-subtle" style={{ padding: 'var(--sp-3)' }}>
    <span className="section-title" style={{ marginBottom: 4, display: 'block' }}>{label}</span>
    {children}
  </div>
);

export default function DownloadCompleteWindow({ downloadId }: any) {
  const [download, setDownload]     = useState<any>(null);
  const [copiedField, setCopiedField] = useState<any>(null);

  useEffect(() => {
    if (downloadId) {
      api.list().then(res => {
        const found = res.items?.find((d: any) => d.id === downloadId);
        if (found) setDownload(found);
      }).catch(console.error);
    }
  }, [downloadId]);

  const close      = () => getCurrentWindow().close().catch(console.error);
  const openFolder = async () => { try { await invoke('show_in_explorer', { path: download.output_path }); } catch {} close(); };
  const openFile   = async () => { try { await invoke('open_file_path',    { path: download.output_path }); } catch {} close(); };
  const copy = (text: string, field: string) => {
    navigator.clipboard.writeText(text);
    setCopiedField(field);
    setTimeout(() => setCopiedField(null), 1500);
  };

  if (!download) return (
    <div style={{ backgroundColor: 'var(--color-surface)', height: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--color-text-4)', fontFamily: 'var(--font-sans)', fontSize: 'var(--text-sm-size)' }}>
      Loading…
    </div>
  );

  const Icon = getFileIcon(download.filename || download.file_name);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', overflow: 'hidden', fontFamily: 'var(--font-sans)', backgroundColor: 'var(--color-surface)', color: 'var(--color-text-1)', userSelect: 'none' }}>
      {/* Title bar */}
      <div className="drag-region" style={{ height: 36, display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 12px', borderBottom: '1px solid var(--color-border)', backgroundColor: 'var(--color-surface-raised)', flexShrink: 0 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 'var(--text-xs-size)', fontWeight: 700, color: 'var(--color-success)' }}>
          <CheckCircle2 size={14} /> Download Complete
        </div>
        <button className="btn-icon no-drag" onClick={close} style={{ width: 28, height: 28 }} title="Close">
          <X size={14} />
        </button>
      </div>

      {/* Body */}
      <div style={{ flex: 1, display: 'flex', gap: 'var(--sp-4)', padding: 'var(--sp-4)', overflow: 'hidden', alignItems: 'center' }}>
        {/* File icon */}
        <div
          onClick={openFile}
          title="Open File"
          style={{
            width: 76, height: 76, flexShrink: 0, cursor: 'default',
            backgroundColor: 'var(--color-brand-dim)', border: '1px solid var(--color-brand)',
            borderRadius: 'var(--radius-lg)', display: 'flex', alignItems: 'center', justifyContent: 'center',
            color: 'var(--color-brand)', transition: 'background-color var(--transition-fast)',
          }}
          onMouseEnter={e => (e.currentTarget.style.backgroundColor = 'var(--color-brand)')}
          onMouseLeave={e => (e.currentTarget.style.backgroundColor = 'var(--color-brand-dim)')}
        >
          <Icon size={36} strokeWidth={1.5} />
        </div>

        {/* Details */}
        <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 'var(--sp-2)', minWidth: 0 }}>
          <InfoCard label="File Name">
            <span className="truncate" style={{ display: 'block', fontWeight: 600, fontSize: 'var(--text-base-size)', color: 'var(--color-text-1)' }} title={download.filename}>{download.filename}</span>
          </InfoCard>

          <div className="grid grid-cols-2 gap-2">
            <InfoCard label="Size">
              <span style={{ fontWeight: 600, fontSize: 'var(--text-sm-size)', color: 'var(--color-text-1)' }}>
                {fmtBytes(download.total_bytes || download.bytes_done)}
              </span>
            </InfoCard>
            <InfoCard label="Integrity">
              {download.hash_result ? (
                <span className={download.hash_result.matched ? 'tag tag-success' : 'tag tag-error'}>
                  {download.hash_result.matched ? 'Matched ✓' : 'Failed ✕'}
                </span>
              ) : (
                <span style={{ color: 'var(--color-text-4)', fontSize: 'var(--text-sm-size)' }}>Unchecked</span>
              )}
            </InfoCard>
          </div>

          <InfoCard label="Save Path">
            <div className="flex items-center gap-2 no-drag">
              <span className="truncate flex-1" style={{ fontSize: 'var(--text-sm-size)', color: 'var(--color-text-2)', userSelect: 'text' }} title={download.output_path}>
                {download.output_path}
              </span>
              <button className="btn-icon" style={{ width: 24, height: 24 }} onClick={() => copy(download.output_path, 'path')} title="Copy path">
                {copiedField === 'path' ? <Check size={12} style={{ color: 'var(--color-success)' }} /> : <Copy size={12} />}
              </button>
            </div>
          </InfoCard>

          <InfoCard label="URL">
            <div className="flex items-center gap-2 no-drag">
              <span className="truncate flex-1" style={{ fontSize: 'var(--text-sm-size)', color: 'var(--color-text-3)', userSelect: 'text' }} title={download.url}>
                {download.url}
              </span>
              <button className="btn-icon" style={{ width: 24, height: 24 }} onClick={() => copy(download.url, 'url')} title="Copy URL">
                {copiedField === 'url' ? <Check size={12} style={{ color: 'var(--color-success)' }} /> : <Copy size={12} />}
              </button>
            </div>
          </InfoCard>
        </div>
      </div>

      {/* Footer */}
      <div className="no-drag" style={{ display: 'flex', alignItems: 'center', justifyContent: 'flex-end', gap: 'var(--sp-2)', padding: '0 var(--sp-4)', height: 48, borderTop: '1px solid var(--color-border)', backgroundColor: 'var(--color-surface-raised)', flexShrink: 0 }}>
        <button className="btn-secondary flex items-center gap-2" onClick={close}><X size={14} /> Close</button>
        <button className="btn-secondary flex items-center gap-2" onClick={openFolder}><FolderOpen size={14} /> Show in Folder</button>
        <button className="btn-primary flex items-center gap-2" onClick={openFile}><Play size={14} /> Open File</button>
      </div>
    </div>
  );
}

﻿import React, { useState, useEffect, useRef } from 'react';
import { getCurrentWindow } from '@tauri-apps/api/window';
import { api, connectSSE, fmtBytes, fmtSpeed, fmtEta } from '../api';
import { X, Activity, HardDrive, ShieldCheck, Folder, FileIcon, Pause, Play, Square, Settings2 } from 'lucide-react';
import { cn } from '../utils';
import { isPermissionGranted, requestPermission, sendNotification } from '@tauri-apps/plugin-notification';

export default function ProgressWindow({ downloadId }: { downloadId: string }) {
  const [item, setItem] = useState<any>(() => {
    try {
      const init = localStorage.getItem(`vajra_progress_init_${downloadId}`);
      if (init) return JSON.parse(init);
    } catch(e) {}
    return null;
  });
  const [speedHistory, setSpeedHistory] = useState<number[]>([]);
  
  const [enableLimit, setEnableLimit] = useState(false);
  const [limitKbps, setLimitKbps] = useState('');
  
  const [showCompleteDialog, setShowCompleteDialog] = useState(false);
  const [shutdownAfterComplete, setShutdownAfterComplete] = useState(false);

  const [connectionMode, setConnectionMode] = useState('sse'); // sse or polling
  const [sseRetries, setSseRetries] = useState(0);

  const lastOverride = useRef<any>(null);

  useEffect(() => {
    const storedComplete = localStorage.getItem(`vajra_show_complete_${downloadId}`);
    if (storedComplete !== null) setShowCompleteDialog(storedComplete === 'true');

    const storedShutdown = localStorage.getItem(`vajra_shutdown_${downloadId}`);
    if (storedShutdown !== null) setShutdownAfterComplete(storedShutdown === 'true');
  }, [downloadId]);

  const updateItemFromPayload = (payload: any) => {
    setItem((prev: any) => {
      let nextStatus = payload.status;
      const now = Date.now();
      const override = lastOverride.current;
      if (override && now - override.timestamp < 1200) {
        nextStatus = override.status;
        if (payload.status === override.status || (override.status === 'connecting' && payload.status === 'downloading')) {
          lastOverride.current = null;
        }
      }

      const prevStatus = prev?.status;
      if ((nextStatus === 'completed' || nextStatus === 'complete') &&
          (prevStatus && prevStatus !== 'completed' && prevStatus !== 'complete')) {
        
        const storedComplete = localStorage.getItem(`vajra_show_complete_${payload.download_id || payload.id}`);
        if (storedComplete === 'true') {
          (async () => {
            try {
              let permissionGranted = await isPermissionGranted();
              if (!permissionGranted) {
                const permission = await requestPermission();
                permissionGranted = permission === 'granted';
              }
              if (permissionGranted) {
                sendNotification({ 
                  title: 'Download Complete', 
                  body: `${payload.filename || payload.file_name || prev?.filename || 'File'} has finished downloading.` 
                });
              }
            } catch (err) {
              console.error("Failed to send notification:", err);
            }
          })();
        }

        setTimeout(() => {
          try { getCurrentWindow().close().catch(console.error); } catch(e) {}
        }, 100);
      }

      return {
        ...prev,
        id: payload.download_id || payload.id,
        filename: payload.filename || payload.file_name || (prev?.filename),
        total_bytes: payload.total_bytes ?? prev?.total_bytes ?? null,
        downloaded_bytes: payload.downloaded_bytes ?? payload.bytes_done ?? prev?.downloaded_bytes ?? 0,
        bytes_done: payload.downloaded_bytes ?? payload.bytes_done ?? prev?.bytes_done ?? 0,
        speed_bps: nextStatus === 'paused' ? 0 : (payload.speed_bps ?? 0),
        eta_seconds: nextStatus === 'paused' ? null : (payload.eta_seconds ?? prev?.eta_seconds ?? null),
        status: nextStatus || prev?.status,
        resume_supported: payload.resume_supported ?? prev?.resume_supported,
        segments: payload.segments || prev?.segments || [],
        url: payload.url || prev?.url,
        output_path: payload.output_path || prev?.output_path,
        error: payload.error,
        hash_result: payload.hash_result || prev?.hash_result,
        expected_hash: payload.expected_hash || prev?.expected_hash
      };
    });

    const currentStatus = payload.status || (item?.status);
    if (payload.speed_bps !== undefined) {
      if (currentStatus === 'downloading') {
        setSpeedHistory(prev => {
          const next = [...prev, payload.speed_bps];
          if (next.length > 50) next.shift();
          return next;
        });
      } else {
        setSpeedHistory(prev => prev.length > 0 && prev[prev.length - 1] === 0 ? prev : [...prev, 0].slice(-50));
      }
    }
  };

  useEffect(() => {
    if (!downloadId) return;
    api.get(downloadId).then(found => {
      if (found) {
        setItem(found as any);
        
        if (found.status === 'completed' || found.status === 'complete') {
          setTimeout(() => {
            try { getCurrentWindow().close().catch(console.error); } catch(e) {}
          }, 100);
        }

        if (found.speed_limit_bps) {
          setEnableLimit(true);
          setLimitKbps(Math.round(found.speed_limit_bps / 1024).toString());
        }
        if (found.speed_bps) setSpeedHistory([found.speed_bps] as any);
      }
    }).catch(console.error);
  }, [downloadId]);

  useEffect(() => {
    if (!downloadId) return;
    let sseCleanup: any = null;
    let pollIntervalId: any = null;
    let sseTimeoutId: any = null;

    const startPolling = (intervalMs: number) => {
      if (pollIntervalId) clearInterval(pollIntervalId);
      const poll = () => {
        api.get(downloadId).then(data => { if (data) updateItemFromPayload(data); }).catch(() => {});
      };
      poll();
      pollIntervalId = setInterval(poll, intervalMs);
    };

    const startSSE = () => {
      if (sseCleanup) { sseCleanup(); sseCleanup = null; }
      sseCleanup = connectSSE((ev: any) => {
        const evId = ev.id || ev.download_id;
        if (!evId || evId.toLowerCase() !== downloadId.toLowerCase()) return;
        setSseRetries(0);
        setConnectionMode('sse');
        if (ev.event === 'progress') {
          updateItemFromPayload(ev);
        } else if (ev.event === 'state_change') {
          let status = ev.status;
          const now = Date.now();
          const override = lastOverride.current as any;
          if (override && now - override.timestamp < 1200) {
            status = override.status;
            if (ev.status === override.status || (override.status === 'connecting' && ev.status === 'downloading')) {
              lastOverride.current = null;
            }
          }
          setItem((prev: any) => {
            const base = prev || {
              id: ev.id || downloadId,
              filename: 'â€”', total_bytes: null, downloaded_bytes: 0, speed_bps: 0,
              eta_seconds: null, resume_supported: false, segments: [], url: 'â€”', output_path: ''
            };
            if ((status === 'completed' || status === 'complete') && base.status !== 'completed' && base.status !== 'complete') {
              const storedComplete = localStorage.getItem(`vajra_show_complete_${ev.id || downloadId}`);
              if (storedComplete === 'true') {
                (async () => {
                  try {
                    let permissionGranted = await isPermissionGranted();
                    if (!permissionGranted) {
                      const permission = await requestPermission();
                      permissionGranted = permission === 'granted';
                    }
                    if (permissionGranted) {
                      sendNotification({ 
                        title: 'Download Complete', 
                        body: `${base.filename || 'File'} has finished downloading.` 
                      });
                    }
                  } catch (err) {
                    console.error("Failed to send notification:", err);
                  }
                })();
              }
              setTimeout(() => { try { getCurrentWindow().close().catch(console.error); } catch(e) {} }, 100);
            }
            return { 
              ...base, 
              status: status, 
              output_path: ev.output_path || base.output_path, 
              error: ev.error,
              hash_result: ev.hash_result || base.hash_result,
              expected_hash: ev.expected_hash || base.expected_hash
            };
          });
        }
      }, (err: any) => {
        if (sseCleanup) { sseCleanup(); sseCleanup = null; }
        setSseRetries(prev => {
          const next = prev + 1;
          if (next >= 3) {
            setConnectionMode('polling');
          } else {
            sseTimeoutId = setTimeout(() => startSSE(), 2000);
          }
          return next;
        });
      });
    };

    if (connectionMode === 'sse') startSSE();
    else {
      startPolling(item?.status === 'paused' ? 5000 : 1500);
      const sseCheckIntervalId = setInterval(() => {
        api.health().then(() => {
          setSseRetries(0);
          setConnectionMode('sse');
        }).catch(() => {});
      }, 30000);
      return () => { clearInterval(pollIntervalId); clearInterval(sseCheckIntervalId); };
    }

    return () => {
      if (sseCleanup) sseCleanup();
      if (pollIntervalId) clearInterval(pollIntervalId);
      if (sseTimeoutId) clearTimeout(sseTimeoutId);
    };
  }, [downloadId, connectionMode, item?.status]);

  const handleClose = () => { getCurrentWindow().close().catch(console.error); };

  const handleApplyLimit = async (e: any) => {
    e.preventDefault();
    try {
      const kbps = parseInt(limitKbps as string, 10);
      const bps = !isNaN(kbps) && kbps > 0 ? kbps * 1024 : 0;
      await api.patch(downloadId, { speed_limit_bps: bps });
      if (bps > 0) setEnableLimit(true);
      else setEnableLimit(false);
    } catch (err) { console.error(err); }
  };

  const handleToggleLimit = async () => {
    const newState = !enableLimit;
    setEnableLimit(newState);
    try {
      if (!newState) {
        await api.patch(downloadId, { speed_limit_bps: 0 });
      } else {
        const kbps = parseInt(limitKbps as string, 10);
        const bps = !isNaN(kbps) && kbps > 0 ? kbps * 1024 : 0;
        await api.patch(downloadId, { speed_limit_bps: bps });
      }
    } catch (e) { console.error(e); }
  };

  const handlePause = async () => {
    lastOverride.current = { status: 'paused', timestamp: Date.now() } as any;
    setItem((prev: any) => prev ? { ...prev, status: 'paused', speed_bps: 0 } as any : null);
    try { await api.patch(downloadId, { action: 'pause' }); } catch(e) { console.error(e); }
  };

  const handleResume = async () => {
    lastOverride.current = { status: 'connecting', timestamp: Date.now() } as any;
    setItem((prev: any) => prev ? { ...prev, status: 'connecting' } as any : null);
    try { await api.patch(downloadId, { action: 'resume' }); } catch(e) { console.error(e); }
  };

  const handleCancel = async () => {
    try { await api.patch(downloadId, { action: 'pause' }); handleClose(); } catch(e) { console.error(e); }
  };

  const handleOpenFolder = async () => {
    try { if (item && (item as any).output_path) { const { invoke } = await import('@tauri-apps/api/core'); await invoke('show_in_explorer', { path: (item as any).output_path }); } } catch (e) { console.error("Failed to open folder", e); }
  };

  const handleOpenFile = async () => {
    try { if (item && (item as any).output_path) { const { invoke } = await import('@tauri-apps/api/core'); await invoke('open_file_path', { path: (item as any).output_path }); } } catch (e) { console.error("Failed to open file", e); }
  };

  const currentItem: any = item || { filename: 'â€”', status: 'connecting', total_bytes: null, downloaded_bytes: 0, speed_bps: 0, eta_seconds: null, resume_supported: false, segments: [], url: 'â€”', output_path: '' };
  
  const dlBytes = currentItem.downloaded_bytes || 0;
  const totBytes = currentItem.total_bytes;
  let pct = 0;
  if (currentItem.status === 'completed') pct = 100;
  else if (totBytes && totBytes > 0) {
    pct = (dlBytes / totBytes) * 100;
    if (pct > 100) pct = 100; // fix overshoot
  }

  const segments = currentItem.segments || [];
  const fileTotal = currentItem.total_bytes || 1;

  const getSegmentColors = (status: string): { track: string; fill: string } => {
    switch (status) {
      case 'completed':  return { track: 'var(--color-success-dim)',  fill: 'var(--color-success)' };
      case 'downloading': return { track: 'var(--color-brand-dim)',   fill: 'var(--color-brand)' };
      case 'paused':     return { track: 'var(--color-warning-dim)',  fill: 'var(--color-warning)' };
      case 'failed':     return { track: 'var(--color-error-dim)',    fill: 'var(--color-error)' };
      default:           return { track: 'var(--color-surface-elevated)', fill: 'var(--color-text-4)' };
    }
  };

  /* Shared inline style values */
  const S = {
    surface:   'var(--color-surface)',
    raised:    'var(--color-surface-raised)',
    elevated:  'var(--color-surface-elevated)',
    border:    'var(--color-border)',
    borderSub: 'var(--color-border-subtle)',
    t1: 'var(--color-text-1)',
    t2: 'var(--color-text-2)',
    t3: 'var(--color-text-3)',
    t4: 'var(--color-text-4)',
    brand: 'var(--color-brand)',
    success: 'var(--color-success)',
    successDim: 'var(--color-success-dim)',
    error: 'var(--color-error)',
  } as const;

  const segStatusColor = (s: string) => {
    if (s === 'downloading') return S.brand;
    if (s === 'completed')   return S.success;
    if (s === 'error' || s === 'failed') return S.error;
    return S.t4;
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', overflow: 'hidden', fontFamily: 'var(--font-sans)', backgroundColor: S.surface, color: S.t1, userSelect: 'none' }}>

      {/* Title bar */}
      <div className="drag-region" style={{ height: 36, display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '0 12px', borderBottom: `1px solid ${S.border}`, backgroundColor: S.raised, flexShrink: 0 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 'var(--text-xs-size)', fontWeight: 600, color: S.t2 }}>
          <Activity size={14} style={{ color: currentItem.status === 'downloading' ? S.brand : S.t4 }} />
          Vajra / {currentItem.status}
        </div>
        <button className="btn-icon no-drag" onClick={handleClose} style={{ width: 28, height: 28 }} title="Close">
          <X size={14} />
        </button>
      </div>

      {/* Body */}
      <div style={{ flex: 1, overflow: 'hidden', display: 'flex', flexDirection: 'column', gap: 6, padding: 8, cursor: 'default' }}>

        {/* File / URL info */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 4, flexShrink: 0, backgroundColor: S.raised, padding: 8, borderRadius: 'var(--radius-lg)', border: `1px solid ${S.border}` }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
            <span className="truncate" style={{ fontWeight: 600, fontSize: 'var(--text-sm-size)', color: S.t1, maxWidth: 400, userSelect: 'text' }} title={currentItem.filename}>
              {currentItem.filename}
            </span>
            <span style={{ fontSize: 'var(--text-xs-size)', fontWeight: 600, color: S.brand, backgroundColor: 'var(--color-brand-dim)', padding: '2px 8px', borderRadius: 'var(--radius-full)', flexShrink: 0 }}>
              {currentItem.filename?.split('.').pop()?.toUpperCase() || 'FILE'}
            </span>
          </div>
          <div style={{ fontSize: 'var(--text-xs-size)', color: S.t4, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', userSelect: 'text' }}>
            <span style={{ color: S.brand, fontWeight: 600 }}>URL: </span>{currentItem.url}
          </div>
          {currentItem.output_path && (
            <div style={{ fontSize: 'var(--text-xs-size)', color: S.t4, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', userSelect: 'text' }}>
              <span style={{ color: S.t3, fontWeight: 600 }}>DIR: </span>{currentItem.output_path}
            </div>
          )}
          {currentItem.expected_hash && (
            <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginTop: 4, paddingTop: 6, borderTop: `1px solid ${S.borderSub}` }}>
              <ShieldCheck size={12} style={{ color: currentItem.hash_result === 'Matched' ? S.success : currentItem.hash_result === 'Mismatched' ? S.error : S.t4 }} />
              <span style={{ fontSize: 'var(--text-xs-size)', fontWeight: 600, color: currentItem.hash_result === 'Matched' ? S.success : currentItem.hash_result === 'Mismatched' ? S.error : S.t4 }}>
                {currentItem.hash_result === 'Matched' ? 'Hash Matched' : currentItem.hash_result === 'Mismatched' ? 'Hash Mismatched' : 'Hash Pending'}
              </span>
              <span style={{ fontSize: 'var(--text-xs-size)', color: S.t4, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{currentItem.expected_hash}</span>
            </div>
          )}
        </div>

        {/* Stats grid */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 6, flexShrink: 0, backgroundColor: S.raised, padding: 8, borderRadius: 'var(--radius-lg)', border: `1px solid ${S.border}` }}>
          {[{
            label: 'Downloaded',
            value: <>{fmtBytes(Math.min(dlBytes, totBytes || dlBytes))} <span style={{ color: S.t4, fontSize: 'var(--text-xs-size)' }}>/ {totBytes ? fmtBytes(totBytes) : '?'}</span></>
          }, {
            label: 'Transfer Rate',
            value: <span style={{ color: S.brand }}>{fmtSpeed(currentItem.speed_bps)}</span>
          }, {
            label: 'Time Left',
            value: fmtEta(currentItem.eta_seconds)
          }, {
            label: 'Threads',
            value: `${segments.length} Active`
          }].map(({ label, value }) => (
            <div key={label} style={{ display: 'flex', flexDirection: 'column' }}>
              <span style={{ fontSize: 'var(--text-xs-size)', color: S.t3, fontWeight: 500 }}>{label}</span>
              <span style={{ fontWeight: 600, color: S.t1, fontSize: 'var(--text-sm-size)', marginTop: 2 }}>{value}</span>
            </div>
          ))}
        </div>

        {/* Controls */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 6, flexShrink: 0 }}>
          {/* Speed limit */}
          <div className="no-drag" style={{ backgroundColor: S.raised, border: `1px solid ${S.border}`, borderRadius: 'var(--radius-lg)', padding: 8, display: 'flex', flexDirection: 'column', gap: 6 }}>
            <button type="button" style={{ display: 'flex', width: '100%', justifyContent: 'space-between', alignItems: 'center', background: 'none', border: 'none', cursor: 'default', padding: 0 }} onClick={handleToggleLimit}>
              <span style={{ fontSize: 'var(--text-xs-size)', fontWeight: 600, color: S.t2, display: 'flex', alignItems: 'center', gap: 4 }}>
                <Settings2 size={13} /> Speed Limit
              </span>
              {/* Toggle pill */}
              <div style={{ width: 28, height: 16, borderRadius: 8, position: 'relative', backgroundColor: enableLimit ? S.brand : S.elevated, border: `1px solid ${S.border}`, transition: 'background-color var(--transition-fast)', flexShrink: 0 }}>
                <div style={{ position: 'absolute', top: 2, width: 10, height: 10, borderRadius: '50%', backgroundColor: 'var(--color-surface)', transition: 'left var(--transition-fast)', left: enableLimit ? 14 : 2 }} />
              </div>
            </button>
            <div style={{ display: 'flex', alignItems: 'center', gap: 4, backgroundColor: S.elevated, borderRadius: 'var(--radius-md)', border: `1px solid ${S.border}`, padding: '0 8px' }}>
              <input
                type="number"
                style={{ background: 'transparent', border: 'none', outline: 'none', color: S.t1, fontSize: 'var(--text-xs-size)', fontWeight: 500, padding: '6px 0', width: '100%' }}
                placeholder="Unlimited"
                value={limitKbps}
                onChange={e => {
                  const val = e.target.value;
                  setLimitKbps(val);
                  const kbps = parseInt(val, 10);
                  if (!isNaN(kbps) && kbps > 0) { setEnableLimit(true); api.patch(downloadId, { speed_limit_bps: kbps * 1024 }).catch(console.error); }
                  else api.patch(downloadId, { speed_limit_bps: 0 }).catch(console.error);
                }}
              />
              <span style={{ fontSize: 'var(--text-xs-size)', color: S.t4, whiteSpace: 'nowrap' }}>KB/s</span>
            </div>
          </div>

          {/* Completion actions */}
          <div className="no-drag" style={{ backgroundColor: S.raised, border: `1px solid ${S.border}`, borderRadius: 'var(--radius-lg)', padding: 8, display: 'flex', flexDirection: 'column', gap: 6 }}>
            <span style={{ fontSize: 'var(--text-xs-size)', fontWeight: 600, color: S.t2, display: 'flex', alignItems: 'center', gap: 4 }}>
              <Settings2 size={13} /> On Completion
            </span>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
              {[{
                label: 'Show Notification', checked: showCompleteDialog,
                onChange: (v: boolean) => { setShowCompleteDialog(v); localStorage.setItem(`vajra_show_complete_${downloadId}`, String(v)); }
              }, {
                label: 'Shutdown PC', checked: shutdownAfterComplete,
                onChange: (v: boolean) => { setShutdownAfterComplete(v); localStorage.setItem(`vajra_shutdown_${downloadId}`, String(v)); }
              }].map(({ label, checked, onChange }) => (
                <label key={label} style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 'var(--text-xs-size)', color: S.t1, cursor: 'default' }}>
                  <input type="checkbox" checked={checked} onChange={e => onChange(e.target.checked)} style={{ accentColor: S.brand, width: 13, height: 13, cursor: 'default' }} />
                  {label}
                </label>
              ))}
            </div>
          </div>
        </div>

        {/* Progress + Speed chart */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 4, flexShrink: 0 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end' }}>
            <span style={{ fontSize: 'var(--text-xs-size)', fontWeight: 600, color: S.t3 }}>Progress</span>
            <span style={{ fontWeight: 700, fontSize: 'var(--text-sm-size)', color: S.brand }}>{pct.toFixed(2)}%</span>
          </div>
          <div style={{ width: '100%', height: 6, backgroundColor: S.elevated, borderRadius: 'var(--radius-full)', overflow: 'hidden', border: `1px solid ${S.border}` }}>
            <div style={{ height: '100%', width: `${pct}%`, backgroundColor: currentItem.status === 'completed' ? S.success : S.brand, transition: 'width 0.3s ease', borderRadius: 'var(--radius-full)' }} />
          </div>
          {currentItem.status !== 'completed' && speedHistory.length >= 2 && (
            <div style={{ position: 'relative', height: 30, width: '100%', backgroundColor: S.raised, borderRadius: 'var(--radius-md)', border: `1px solid ${S.border}`, overflow: 'hidden', flexShrink: 0 }}>
              <svg viewBox="0 0 500 30" style={{ position: 'absolute', inset: 0, width: '100%', height: '100%' }} preserveAspectRatio="none">
                <defs><linearGradient id="chartGrad" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={S.brand} stopOpacity={0.3} /><stop offset="100%" stopColor={S.brand} stopOpacity={0} /></linearGradient></defs>
                <path d={`M 0,30 L ${speedHistory.map((s, i) => { const x = (i/(speedHistory.length-1))*500; const mx = Math.max(...speedHistory as any, 1024*1024); const y = 30 - ((s as any)/mx)*30*0.8 - 1; return `${x},${y}`; }).join(' ')} L 500,30 Z`} fill="url(#chartGrad)" />
                <polyline fill="none" stroke={S.brand} strokeWidth="1.5" points={speedHistory.map((s, i) => { const x = (i/(speedHistory.length-1))*500; const mx = Math.max(...speedHistory as any, 1024*1024); const y = 30-((s as any)/mx)*30*0.8-1; return `${x},${y}`; }).join(' ')} />
              </svg>
            </div>
          )}
        </div>

        {/* Segment bar + thread table */}
        {currentItem.status !== 'completed' && segments.length > 0 && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 4, flex: 1, minHeight: 0 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 'var(--text-xs-size)', color: S.t3 }}>
              <span style={{ fontWeight: 600 }}>Thread Distribution</span>
              <span style={{ fontWeight: 600 }}>{segments.length} Connections</span>
            </div>
            {/* Segment bar */}
            <div style={{ display: 'flex', width: '100%', height: 8, gap: 1, backgroundColor: S.elevated, borderRadius: 'var(--radius-md)', overflow: 'hidden', border: `1px solid ${S.border}` }}>
              {segments.map((seg: any, idx: number) => {
                const wp  = fileTotal > 0 ? (seg.allocated_bytes / fileTotal) * 100 : (100 / segments.length);
                const fp  = seg.allocated_bytes > 0 ? Math.min(100, Math.max(0, (seg.bytes_done / seg.allocated_bytes) * 100)) : 0;
                const col = getSegmentColors(seg.status);
                return (
                  <div key={seg.id ?? idx} style={{ position: 'relative', height: '100%', width: `${wp}%`, minWidth: 1, backgroundColor: col.track }}>
                    <div style={{ position: 'absolute', top: 0, bottom: 0, left: 0, width: `${fp}%`, backgroundColor: col.fill, transition: 'width 0.3s ease' }} />
                  </div>
                );
              })}
            </div>
            {/* Thread table */}
            <div style={{ flex: 1, minHeight: 60, border: `1px solid ${S.border}`, borderRadius: 'var(--radius-md)', backgroundColor: S.raised, overflow: 'hidden' }}>
              <div style={{ overflowY: 'auto', height: '100%' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 'var(--text-xs-size)' }}>
                  <thead style={{ position: 'sticky', top: 0, backgroundColor: S.raised, zIndex: 1, borderBottom: `1px solid ${S.border}` }}>
                    <tr>
                      {['Connection', 'Progress', 'Status'].map((h, i) => (
                        <th key={h} style={{ padding: '6px 10px', fontWeight: 600, color: S.t3, textAlign: i === 2 ? 'right' : 'left', whiteSpace: 'nowrap' }}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {segments.map((seg: any, idx: number) => (
                      <tr key={seg.id ?? idx} style={{ borderBottom: `1px solid ${S.borderSub}` }}
                        onMouseEnter={e => (e.currentTarget.style.backgroundColor = S.elevated)}
                        onMouseLeave={e => (e.currentTarget.style.backgroundColor = 'transparent')}>
                        <td style={{ padding: '5px 10px', fontWeight: 500, color: S.t1, whiteSpace: 'nowrap' }}>Thread {idx + 1}</td>
                        <td style={{ padding: '5px 10px', color: S.t3, whiteSpace: 'nowrap' }}>{fmtBytes(seg.bytes_done)} / {seg.allocated_bytes > 0 ? fmtBytes(seg.allocated_bytes) : '???'}</td>
                        <td style={{ padding: '5px 10px', fontWeight: 600, color: segStatusColor(seg.status), textAlign: 'right', whiteSpace: 'nowrap' }}>{(seg.status || 'unknown').toUpperCase()}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {/* Completion banner */}
        {currentItem.status === 'completed' && (
          <div className="no-drag" style={{ marginTop: 4, backgroundColor: 'var(--color-success-dim)', border: `1px solid ${S.success}`, borderRadius: 'var(--radius-lg)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '10px 12px' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 6, color: S.success, fontWeight: 600, fontSize: 'var(--text-sm-size)' }}>
              <ShieldCheck size={16} /> Download Complete
            </div>
            <div style={{ display: 'flex', gap: 6 }}>
              <button className="btn-secondary flex items-center gap-2" onClick={handleOpenFolder}><Folder size={13} /> Folder</button>
              <button className="btn-primary flex items-center gap-2" onClick={handleOpenFile}><FileIcon size={13} /> Open</button>
            </div>
          </div>
        )}
      </div>

      {/* Footer */}
      <div style={{ height: 48, padding: '0 16px', borderTop: `1px solid ${S.border}`, backgroundColor: S.raised, display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexShrink: 0, userSelect: 'none' }}>
        <button className="btn-secondary" onClick={handleClose}>Hide Window</button>
        <div className="flex gap-2 no-drag">
          {(currentItem.status === 'downloading' || currentItem.status === 'connecting') && (
            <button className="btn-primary flex items-center gap-2" onClick={handlePause}><Pause size={13} /> Pause</button>
          )}
          {(currentItem.status === 'paused' || currentItem.status === 'failed') && (
            <button className="btn-primary flex items-center gap-2" onClick={handleResume}><Play size={13} /> Resume</button>
          )}
          {currentItem.status !== 'completed' && (
            <button className="btn-danger flex items-center gap-2" onClick={handleCancel}><Square size={13} /> Stop</button>
          )}
        </div>
      </div>
    </div>
  );
}
